const e=[{id:"compressor_no_start",title:"압축기가 안 돌아간다",title_en:"Compressor does not start",icon:"⚙️",startNode:"cn_q1"},{id:"poor_cooling",title:"냉각이 안 된다 / 온도가 안 내려간다",title_en:"Not cooling / temperature won't drop",icon:"🌡️",startNode:"pc_q1"},{id:"abnormal_noise",title:"이상한 소음이 난다",title_en:"Abnormal noise",icon:"🔊",startNode:"an_q1"},{id:"breaker_trip",title:"전기가 자꾸 끊긴다 (차단기 트립)",title_en:"Circuit breaker keeps tripping",icon:"⚡",startNode:"bt_q1"},{id:"heavy_frost",title:"서리(착상)가 너무 많이 낀다",title_en:"Excessive frost buildup",icon:"❄️",startNode:"hf_q1"},{id:"short_cycling",title:"압축기가 자꾸 껐다 켜진다",title_en:"Compressor short cycling",icon:"🔄",startNode:"sc_q1"},{id:"high_pressure",title:"고압 스위치가 자꾸 동작한다",title_en:"High pressure switch keeps tripping",icon:"📈",startNode:"hp_q1"},{id:"low_pressure",title:"저압 스위치가 자꾸 동작한다",title_en:"Low pressure switch keeps tripping",icon:"📉",startNode:"lp_q1"},{id:"evap_fan_fail",title:"증발기 팬이 안 돌아간다",title_en:"Evaporator fan not running",icon:"💨",startNode:"ef_q1"},{id:"cond_fan_fail",title:"응축기 팬이 안 돌아간다",title_en:"Condenser fan not running",icon:"🌀",startNode:"cf_q1"},{id:"drainage_issue",title:"물(결로)이 흘러내린다",title_en:"Water dripping / drain blocked",icon:"💧",startNode:"dr_q1"},{id:"no_power",title:"냉동기가 전혀 반응이 없다",title_en:"Unit completely dead",icon:"🔌",startNode:"np_q1"}],t={cn_q1:{question:"전원을 켰을 때 컨트롤러 화면이나 표시등이 켜지나요?",question_en:"Does the controller display or indicator light turn on when powered?",yes:"cn_q2",no:"cn_q1n"},cn_q1n:{question:"차단기가 내려가 있거나 퓨즈가 끊어져 있나요?",question_en:"Is the circuit breaker tripped or a fuse blown?",yes:"cn_q1n_y",no:"cn_q1n_n"},cn_q1n_n:{question:"전원 입력 단자에서 전압이 측정되나요? (AC 220V 또는 380V)",question_en:"Is voltage measured at the power input terminals? (AC 220V or 380V)",yes:"cn_q1n_n_y",no:"cn_r_no_input"},cn_q1n_n_y:{question:"메인 수동 스위치(비상정지 등)가 ON 위치에 있나요?",question_en:"Is the main manual switch (emergency stop, etc.) in the ON position?",yes:"cn_r_wiring_main",no:"cn_r_switch_off"},cn_q1n_y:{question:"차단기를 올리면 즉시(1~2초 이내) 다시 내려가나요?",question_en:"Does the breaker trip again immediately (within 1–2 seconds) when reset?",yes:"cn_q1n_y_instant",no:"cn_q1n_y_delay"},cn_q1n_y_instant:{question:"모든 부하를 분리한 후에도 차단기가 트립되나요?",question_en:"Does the breaker still trip after disconnecting all loads?",yes:"cn_r_wiring_short",no:"cn_q1n_y_instant_load"},cn_q1n_y_instant_load:{question:"압축기만 연결했을 때 트립되나요?",question_en:"Does it trip when only the compressor is connected?",yes:"cn_q1n_y_instant_comp",no:"cn_r_other_load_short"},cn_q1n_y_instant_comp:{question:"압축기 각 단자 → 대지(접지) 절연저항이 1MΩ 미만인가요?",question_en:"Is the insulation resistance from any compressor terminal to ground below 1MΩ?",yes:"cn_r_comp_ground",no:"cn_r_comp_winding_short"},cn_q1n_y_delay:{question:"차단기 용량이 최대 운전전류 × 1.25 이상인가요?",question_en:"Is the breaker rated current at least 1.25× the maximum operating current?",yes:"cn_q1n_y_delay_ok",no:"cn_r_breaker_small"},cn_q1n_y_delay_ok:{question:"클램프미터로 기동 전류를 측정했을 때 정격 전류의 6배를 초과하나요?",question_en:"Does the measured inrush current exceed 6× the rated current (measured with clamp meter)?",yes:"cn_r_high_inrush",no:"cn_r_breaker_old"},cn_q2:{question:"설정 온도보다 현재 온도가 높아서 압축기가 운전을 요청하는 상태인가요?",question_en:"Is the current temperature above the setpoint, requiring the compressor to run?",yes:"cn_q3",no:"cn_q2n"},cn_q2n:{question:"운전/정지 타이머나 디프로스트(제상) 타이머가 동작 중인가요?",question_en:"Is an operating timer or defrost timer currently active?",yes:"cn_r_timer_active",no:"cn_q2n_n"},cn_q2n_n:{question:"온도 센서 저항값을 측정했나요? (기종별 NTC 특성표 참고)",question_en:"Have you measured the temperature sensor resistance? (refer to model-specific NTC table)",yes:"cn_q2n_n_y",no:"cn_r_measure_sensor"},cn_q2n_n_y:{question:"센서 저항값이 현재 온도에 해당하는 정상 범위 안에 있나요?",question_en:"Is the sensor resistance within the normal range for the current temperature?",yes:"cn_r_controller_out",no:"cn_r_sensor_bad"},cn_q3:{question:"접촉기(마그네틱 컨택터)가 동작하나요? (딸깍 소리 또는 보조 접점 LED 확인)",question_en:"Does the magnetic contactor operate? (listen for click or check auxiliary LED)",yes:"cn_q4",no:"cn_q3n"},cn_q3n:{question:"과부하 릴레이(THR/EOCR)가 트립 상태인가요? (표시등 또는 버튼 돌출 확인)",question_en:"Is the overload relay (THR/EOCR) in tripped state? (check indicator or protruding reset button)",yes:"cn_q3n_thr",no:"cn_q3n_nothr"},cn_q3n_thr:{question:"릴레이를 수동 리셋한 후 즉시 다시 트립되나요?",question_en:"Does the relay trip again immediately after manual reset?",yes:"cn_q3n_thr_instant",no:"cn_q3n_thr_delay"},cn_q3n_thr_instant:{question:"현재 압축기 운전 전류가 정격 전류를 초과하고 있나요?",question_en:"Is the current compressor operating current exceeding the rated value?",yes:"cn_q3n_thr_oc",no:"cn_r_thr_setpoint"},cn_q3n_thr_oc:{question:"고압(토출) 압력이 정상보다 높게 측정되나요?",question_en:"Is the discharge (high-side) pressure measuring above normal?",yes:"cn_r_overcurrent_hp",no:"cn_q3n_thr_oc_n"},cn_q3n_thr_oc_n:{question:"단상 압축기에서 기동 콘덴서 용량이 부족하지 않나요?",question_en:"For single-phase compressors: is the start capacitor capacity insufficient?",yes:"cn_r_cap_oc",no:"cn_r_comp_overload"},cn_q3n_thr_delay:{question:"10분 냉각 후 재기동 시 다시 트립되나요?",question_en:"Does it trip again after 10-minute cooling and restart?",yes:"cn_r_overload_persistent",no:"cn_r_overload_once"},cn_q3n_nothr:{question:"고압 차단 스위치(HPS) 또는 저압 차단 스위치(LPS)가 동작 상태인가요?",question_en:"Is the high pressure switch (HPS) or low pressure switch (LPS) activated?",yes:"cn_q3n_nothr_sw",no:"cn_q3n_nothr_nosw"},cn_q3n_nothr_sw:{question:"고압 스위치(HPS)가 동작했나요? (저압이 아닌 고압 스위치)",question_en:"Is it the high pressure switch (HPS) that tripped? (not the low pressure switch)",yes:"cn_r_hps_trip",no:"cn_r_lps_trip"},cn_q3n_nothr_nosw:{question:"컨트롤러(온도조절기/타이머)가 접촉기 코일에 신호(전압)를 보내고 있나요?",question_en:"Is the controller (thermostat/timer) sending a signal (voltage) to the contactor coil?",yes:"cn_q3n_nothr_sig",no:"cn_r_controller_no_signal"},cn_q3n_nothr_sig:{question:"접촉기 코일 저항을 측정했을 때 단선(∞)은 아닌가요?",question_en:"When measuring the contactor coil resistance, is it NOT open-circuit (∞)?",yes:"cn_r_contactor_wiring",no:"cn_r_contactor_coil"},cn_q4:{question:"압축기 단자에서 전압이 직접 측정되나요? (접촉기 출력측 → 압축기 단자)",question_en:"Is voltage measured directly at the compressor terminals? (contactor output → compressor terminals)",yes:"cn_q5",no:"cn_q4n"},cn_q4n:{question:"접촉기 출력 단자(2차측)에서는 전압이 나오나요?",question_en:"Is voltage present at the contactor output terminals (secondary side)?",yes:"cn_r_wiring_comp",no:"cn_r_contactor_contact"},cn_q5:{question:"기동 시 '웅~' 하는 소리가 나지만 회전하지 않나요?",question_en:"Does the compressor hum during startup but fail to rotate?",yes:"cn_q5y",no:"cn_q5n"},cn_q5y:{question:"단상(220V) 압축기인가요?",question_en:"Is this a single-phase (220V) compressor?",yes:"cn_q5y_single",no:"cn_q5y_three"},cn_q5y_single:{question:"기동 콘덴서 용량을 측정했나요? 정격값의 ±20% 이내인가요?",question_en:"Have you measured the start capacitor? Is it within ±20% of the rated value?",yes:"cn_q5y_single_ok",no:"cn_r_capacitor"},cn_q5y_single_ok:{question:"압축기를 손으로 살짝 돌려봤을 때 기동되나요? (극성 바꿔서 시도)",question_en:"Does the compressor start if you manually turn the shaft slightly? (try reversing polarity)",yes:"cn_r_seized_light",no:"cn_r_start_winding"},cn_q5y_three:{question:"3상 결선 순서(R-S-T)와 전압 불평형을 확인했나요? 정상인가요?",question_en:"Have you checked the 3-phase wiring order (R-S-T) and voltage balance? Is it normal?",yes:"cn_r_comp_3ph_fault",no:"cn_r_phase_issue"},cn_q5n:{question:"아무 소리도 없이 완전히 무반응인가요?",question_en:"Is there absolutely no sound or response at all?",yes:"cn_q5n_silent",no:"cn_q5n_sound"},cn_q5n_sound:{question:"짧게 '딸깍' 또는 '툭' 소리만 나고 바로 멈추나요?",question_en:"Is there just a brief 'click' or 'thud' sound and then it immediately stops?",yes:"cn_r_thermal_prot",no:"cn_r_voltage_unstable"},cn_q5n_silent:{question:"압축기 단자간(C-S, C-R, S-R) 저항을 측정했나요?",question_en:"Have you measured resistance between compressor terminals (C-S, C-R, S-R)?",yes:"cn_q5n_silent_res",no:"cn_r_measure_resistance"},cn_q5n_silent_res:{question:"C-S, C-R, S-R 중 저항값이 0Ω(단락) 또는 무한대(∞, 단선)인 것이 있나요?",question_en:"Is any of C-S, C-R, S-R measuring 0Ω (short) or infinite (∞, open)?",yes:"cn_r_winding_fault",no:"cn_q5n_silent_ins"},cn_q5n_silent_ins:{question:"압축기 단자 → 대지 절연저항이 1MΩ 미만인가요?",question_en:"Is the insulation resistance from compressor terminals to ground below 1MΩ?",yes:"cn_r_ground_fault",no:"cn_r_seized"},cn_r_no_input:{type:"result",title:"외부 전원 공급 없음",title_en:"No external power supply",causes:["건물 메인 차단기 트립","한전 정전 또는 단선","인입 케이블 단선"],causes_en:["Building main breaker tripped","Utility power outage or line break","Service cable broken"],steps:["1. 건물 메인 차단기 상태 확인","2. 인근 다른 콘센트에 전원 있는지 확인","3. 인입 케이블 단선 여부 점검","4. 전기 공사 업체 연락"],steps_en:["1. Check building main breaker","2. Verify power at nearby outlets","3. Inspect service cable for breaks","4. Contact electrical contractor"],level:"easy"},cn_r_switch_off:{type:"result",title:"메인 스위치 오프 상태",title_en:"Main switch is OFF",causes:["수동 비상정지 스위치 OFF","절전 스위치 OFF"],causes_en:["Manual emergency stop switch OFF","Power-saving switch OFF"],steps:["1. 메인 스위치를 ON으로 전환","2. 재기동 시도","3. 정기 점검 후 스위치 OFF가 반복되면 표시 라벨 부착"],steps_en:["1. Turn main switch to ON","2. Attempt restart","3. If switch is repeatedly found OFF, add a label"],level:"easy"},cn_r_wiring_main:{type:"result",title:"판넬 내부 배선 문제",title_en:"Internal panel wiring issue",causes:["차단기 → 컨트롤러 배선 단선","단자 접촉 불량","배선 피복 손상"],causes_en:["Wiring break from breaker to controller","Terminal contact failure","Wiring insulation damage"],steps:["1. 판넬 내부 배선 연결 상태 전체 점검","2. 단자대 나사 조임 상태 확인","3. 피복 손상 구간 교체 또는 절연 처리"],steps_en:["1. Inspect all internal panel wiring connections","2. Check terminal block screw tightness","3. Replace or insulate any damaged wiring"],level:"medium"},cn_r_wiring_short:{type:"result",title:"배선 단락 또는 차단기 불량",title_en:"Wiring short circuit or defective breaker",causes:["배선 절연 파괴로 단락","차단기 자체 불량","습기·결로에 의한 트래킹"],causes_en:["Wiring insulation failure causing short","Defective breaker","Tracking due to moisture/condensation"],steps:["1. 배선 전체 절연저항 측정 (각 선 → 대지)","2. 손상 구간 교체","3. 차단기 단품 테스트 (다른 부하로 확인)","4. 원인 해결 후 차단기 교체"],steps_en:["1. Measure insulation resistance for all wiring (each line to ground)","2. Replace damaged sections","3. Test breaker separately with another load","4. Replace breaker after resolving root cause"],level:"hard",warning:"단락 상태에서 반복 투입 금지 - 화재 위험",warning_en:"Do NOT repeatedly close breaker under short circuit — fire risk"},cn_r_other_load_short:{type:"result",title:"다른 부하(팬·컨트롤러 등) 단락",title_en:"Short circuit in another load (fan, controller, etc.)",causes:["팬 모터 권선 단락","컨트롤러 전원부 단락","히터 단락"],causes_en:["Fan motor winding short","Controller power supply short","Heater short"],steps:["1. 팬 모터, 컨트롤러, 히터 등 부하를 하나씩 연결하며 트립 부하 특정","2. 특정된 부하의 절연저항 측정","3. 불량 부품 교체"],steps_en:["1. Connect loads one by one to identify which causes the trip","2. Measure insulation resistance of identified load","3. Replace faulty component"],level:"medium"},cn_r_comp_ground:{type:"result",title:"압축기 권선 지락",title_en:"Compressor winding ground fault",causes:["권선 절연 노후 파괴","수분·냉동유 오염에 의한 절연 저하","과열에 의한 절연 손상"],causes_en:["Aged winding insulation breakdown","Insulation degradation from moisture/oil contamination","Insulation damage from overheating"],steps:["1. 냉매 완전 회수","2. 냉동유 오염 확인 (산성화 여부)","3. 압축기 교체","4. 시스템 플러싱 후 드라이어 교체 필수","5. 신규 냉매 재충전"],steps_en:["1. Fully recover refrigerant","2. Check oil contamination (acidity)","3. Replace compressor","4. Flush system and replace filter-drier (mandatory)","5. Recharge with new refrigerant"],level:"hard",warning:"권선 소손 시 산성 오일이 계통 오염 - 플러싱 필수",warning_en:"Burned windings contaminate system with acid oil — flushing mandatory"},cn_r_comp_winding_short:{type:"result",title:"압축기 권선 단락",title_en:"Compressor winding short circuit",causes:["권선 절연 파괴 후 선간 단락","권선 소손"],causes_en:["Inter-winding short after insulation failure","Winding burnout"],steps:["1. 냉매 회수 후 압축기 교체","2. 산성화된 오일 제거를 위한 플러싱","3. 드라이어 교체 후 재충전"],steps_en:["1. Recover refrigerant and replace compressor","2. Flush to remove acidic oil","3. Replace filter-drier and recharge"],level:"hard",warning:"단락 후 재기동 시 추가 손상 및 화재 위험",warning_en:"Restarting after short circuit risks further damage and fire"},cn_r_breaker_small:{type:"result",title:"차단기 용량 부족",title_en:"Undersized circuit breaker",causes:["차단기 정격 전류 부족","부하 증가 후 차단기 미변경"],causes_en:["Breaker rated current too low","Breaker not upgraded after load increase"],steps:["1. 최대 운전 전류 측정","2. 정격 전류 = 최대 전류 × 1.25 이상으로 선정","3. 동일 극수·차단용량의 적정 용량 차단기로 교체"],steps_en:["1. Measure maximum operating current","2. Select rated current = max current × 1.25 or higher","3. Replace with properly rated breaker of same pole count and breaking capacity"],level:"easy"},cn_r_high_inrush:{type:"result",title:"기동 전류 과다 - 콘덴서 불량 또는 역상",title_en:"Excessive inrush current — capacitor fault or phase reversal",causes:["기동 콘덴서 용량 저하","3상 역상으로 인한 기동 실패","결상(한 상 단선)"],causes_en:["Start capacitor capacity degraded","Phase reversal causing start failure","Phase loss (one phase broken)"],steps:["1. 단상이면: 콘덴서 용량 측정 후 교체","2. 3상이면: 각 상 전압 및 결선 순서 확인","3. 역상 확인 시 두 선 교환","4. 결상 확인 시 단선 구간 수리"],steps_en:["1. Single-phase: measure and replace capacitor","2. Three-phase: check each phase voltage and wiring order","3. If phase reversal: swap two wires","4. If phase loss: repair broken line"],level:"medium"},cn_r_breaker_old:{type:"result",title:"차단기 노후 불량",title_en:"Aged/defective circuit breaker",causes:["차단기 10년 이상 노후로 특성 열화","트립 전류 설정값 낮아짐"],causes_en:["Breaker over 10 years old with degraded characteristics","Trip current threshold has dropped"],steps:["1. 차단기 제조년도 확인 (10년 이상이면 교체 권장)","2. 동일 규격 차단기로 교체","3. 교체 후 기동 테스트"],steps_en:["1. Check breaker manufacture date (recommend replacement if over 10 years)","2. Replace with same-spec breaker","3. Test startup after replacement"],level:"easy"},cn_r_timer_active:{type:"result",title:"타이머/제상 동작 중 - 정상 대기 상태",title_en:"Timer/defrost active — normal standby state",causes:["운전 정지 타이머 동작 중","제상(디프로스트) 사이클 진행 중"],causes_en:["Operating stop timer active","Defrost cycle in progress"],steps:["1. 타이머 동작 완료까지 대기","2. 제상 중이면 제상 완료 후 자동 재기동 확인","3. 비정상적으로 길면 타이머 설정값 점검"],steps_en:["1. Wait for timer cycle to complete","2. If defrosting, confirm auto-restart after defrost ends","3. If unusually long, check timer settings"],level:"easy"},cn_r_measure_sensor:{type:"result",title:"온도 센서 측정 필요",title_en:"Temperature sensor measurement needed",causes:["점검 미실시"],causes_en:["Inspection not yet performed"],steps:["1. 멀티미터 저항 모드로 센서 양단 저항 측정","2. 기종별 NTC 특성표와 비교 (현재 온도 기준)","3. 단선(∞) 또는 단락(0Ω) 여부 확인"],steps_en:["1. Measure resistance across sensor with multimeter in resistance mode","2. Compare with model-specific NTC table at current temperature","3. Check for open (∞) or short (0Ω)"],level:"easy"},cn_r_sensor_bad:{type:"result",title:"온도 센서 불량",title_en:"Temperature sensor defective",causes:["NTC 서미스터 노후","배선 단선 또는 단락","센서 접촉 불량"],causes_en:["Aged NTC thermistor","Wiring open or short","Sensor contact failure"],steps:["1. 센서 배선 점검 (단선·단락)","2. 동일 규격 센서로 교체","3. 교체 후 컨트롤러에서 온도 정상 표시 확인"],steps_en:["1. Check sensor wiring (open/short)","2. Replace with same-spec sensor","3. After replacement, confirm normal temperature reading on controller"],level:"easy"},cn_r_controller_out:{type:"result",title:"컨트롤러 출력 회로 불량",title_en:"Controller output circuit failure",causes:["컨트롤러 릴레이 출력 접점 소손","컨트롤러 PCB 불량"],causes_en:["Controller relay output contact burned","Controller PCB failure"],steps:["1. 컨트롤러 출력 단자에서 전압 출력 여부 확인","2. 출력 없으면 컨트롤러 교체","3. 동일 기종 컨트롤러 구입 후 교체"],steps_en:["1. Check for voltage output at controller output terminals","2. If no output, replace controller","3. Purchase and install same-model controller"],level:"medium"},cn_r_controller_no_signal:{type:"result",title:"컨트롤러/타이머 신호 미출력",title_en:"No signal from controller/timer",causes:["온도 설정 오류 (설정온도가 현재온도보다 낮음)","타이머 설정 오류","컨트롤러 불량"],causes_en:["Temperature setpoint below current temperature","Timer setting error","Controller malfunction"],steps:["1. 온도 설정값 확인 및 현재 온도보다 높게 설정","2. 타이머 설정 확인 (운전 시간대 점검)","3. 설정 정상인데 신호 없으면 컨트롤러 교체"],steps_en:["1. Check temperature setpoint and set above current temperature","2. Check timer settings (verify operating time periods)","3. If settings are correct but no signal, replace controller"],level:"easy"},cn_r_thr_setpoint:{type:"result",title:"과부하 릴레이 설정값 오류",title_en:"Overload relay setpoint error",causes:["THR 설정 전류값이 너무 낮게 조정됨","다른 기종 릴레이 사용으로 불일치"],causes_en:["THR current setting adjusted too low","Mismatch from using different model relay"],steps:["1. 압축기 정격 전류 확인 (명판 확인)","2. THR 설정 다이얼을 정격 전류 × 1.1 수준으로 조정","3. 리셋 후 기동 테스트"],steps_en:["1. Check compressor rated current (nameplate)","2. Adjust THR dial to approximately rated current × 1.1","3. Reset and test startup"],level:"easy"},cn_r_overcurrent_hp:{type:"result",title:"고압 상승으로 인한 과전류",title_en:"Overcurrent due to high discharge pressure",causes:["응축기 핀 오염으로 열방출 불량","응축기 팬 고장","냉매 과충전"],causes_en:["Condenser fin fouling causing poor heat rejection","Condenser fan failure","Refrigerant overcharge"],steps:["1. 응축기 팬 동작 확인","2. 응축기 핀 상태 확인 및 세척","3. 고압 측정 - 정상값 초과 시 냉매 회수 조정","4. 원인 해결 후 THR 리셋 → 재기동"],steps_en:["1. Verify condenser fan operation","2. Inspect and clean condenser fins","3. Measure high-side pressure — recover refrigerant if above normal","4. After resolving, reset THR and restart"],level:"medium"},cn_r_cap_oc:{type:"result",title:"기동 콘덴서 불량으로 과전류",title_en:"Overcurrent due to defective start capacitor",causes:["기동 콘덴서 용량 저하로 기동 전류 지속"],causes_en:["Prolonged inrush current due to reduced start capacitor capacity"],steps:["1. 전원 차단 후 콘덴서 방전 (안전 필수)","2. 콘덴서 용량 측정","3. 동일 규격(μF, V)으로 교체","4. THR 리셋 후 기동 테스트"],steps_en:["1. Cut power and discharge capacitor (safety essential)","2. Measure capacitor capacity","3. Replace with same spec (μF, V)","4. Reset THR and test startup"],level:"easy"},cn_r_comp_overload:{type:"result",title:"압축기 자체 과부하 (내부 마모)",title_en:"Compressor internal overload (internal wear)",causes:["압축기 내부 마찰 증가 (베어링 마모, 냉동유 부족)","실린더/피스톤 마모로 효율 저하"],causes_en:["Increased internal friction (bearing wear, oil shortage)","Reduced efficiency from cylinder/piston wear"],steps:["1. 냉동유 레벨 확인 및 보충","2. 운전 전류 정밀 측정 및 기록","3. 압축기 교체 검토 (전류가 정격 대비 20% 이상 초과 시)"],steps_en:["1. Check and top up oil level","2. Precisely measure and record operating current","3. Consider compressor replacement (if current exceeds rated by 20% or more)"],level:"hard"},cn_r_overload_persistent:{type:"result",title:"지속적 과부하 - 계통 원인 조사 필요",title_en:"Persistent overload — system cause investigation needed",causes:["냉매 과충전 (고압 상승)","응축기 오염 (고압 상승)","냉동유 부족 (마찰 증가)","흡입 배관 막힘"],causes_en:["Refrigerant overcharge (high pressure)","Condenser fouling (high pressure)","Oil shortage (increased friction)","Suction line blockage"],steps:["1. 고압·저압 동시 측정","2. 응축기 상태 및 팬 동작 확인","3. 냉동유 레벨 확인","4. 원인 별 조치 후 재기동"],steps_en:["1. Measure both high and low side pressures simultaneously","2. Check condenser condition and fan operation","3. Check oil level","4. Address each cause and restart"],level:"medium"},cn_r_overload_once:{type:"result",title:"일시적 과열 트립 - 원인 모니터링 필요",title_en:"Temporary thermal overload — monitoring needed",causes:["기동 실패 반복으로 권선 과열","주변 온도 일시 상승"],causes_en:["Winding overheat from repeated failed starts","Temporary ambient temperature spike"],steps:["1. 10분 이상 냉각 대기","2. 재기동 후 운전 전류 즉시 측정 및 기록","3. 재발하면 과부하 원인 정밀 점검"],steps_en:["1. Allow at least 10 minutes to cool","2. Measure operating current immediately after restart and record","3. If it recurs, perform detailed overload investigation"],level:"easy"},cn_r_hps_trip:{type:"result",title:"고압 스위치 동작으로 압축기 정지",title_en:"Compressor stopped by high pressure switch",causes:["응축기 핀 오염","응축기 팬 고장","냉매 과충전","불응축 가스 혼입"],causes_en:["Condenser fin fouling","Condenser fan failure","Refrigerant overcharge","Non-condensable gas contamination"],steps:["1. 고압 측정 (정상치 확인)","2. 응축기 팬 동작 확인","3. 응축기 세척","4. 원인 해결 후 HPS 수동 리셋","5. 재발 방지를 위해 냉매 충전량 재확인"],steps_en:["1. Measure high-side pressure","2. Check condenser fan operation","3. Clean condenser","4. Manually reset HPS after resolving cause","5. Verify refrigerant charge to prevent recurrence"],level:"medium"},cn_r_lps_trip:{type:"result",title:"저압 스위치 동작으로 압축기 정지",title_en:"Compressor stopped by low pressure switch",causes:["냉매 누설로 인한 부족","팽창밸브 과도하게 닫힘","흡입 스트레이너 막힘"],causes_en:["Refrigerant shortage from leak","Expansion valve too closed","Suction strainer clogged"],steps:["1. 저압 측정 (정상치 확인)","2. 사이트글라스 기포 확인","3. 냉매 누설 점검 (비눗물)","4. 팽창밸브 감온통 밀착 확인","5. 원인 해결 후 LPS 리셋"],steps_en:["1. Measure low-side pressure","2. Check sight glass for bubbles","3. Check for refrigerant leaks (soapy water)","4. Verify expansion valve sensing bulb contact","5. Reset LPS after resolving cause"],level:"medium"},cn_r_contactor_wiring:{type:"result",title:"접촉기 코일 배선 접촉 불량",title_en:"Poor contact in contactor coil wiring",causes:["코일 전원 배선 단자 이완","배선 피복 손상으로 단선"],causes_en:["Coil power wiring terminal loose","Wiring broken due to insulation damage"],steps:["1. 접촉기 코일 전원 단자 나사 조임","2. 코일 입력 배선 점검 및 교체","3. 재기동 테스트"],steps_en:["1. Tighten contactor coil power terminal screws","2. Inspect and replace coil input wiring","3. Test restart"],level:"easy"},cn_r_contactor_coil:{type:"result",title:"접촉기 코일 단선",title_en:"Contactor coil open circuit",causes:["코일 권선 단선 (노후)","과전압에 의한 코일 소손"],causes_en:["Coil winding open (aged)","Coil burned from overvoltage"],steps:["1. 동일 전압·규격의 접촉기 코일 또는 접촉기 전체 교체","2. 교체 후 코일 전압 재확인","3. 기동 테스트"],steps_en:["1. Replace contactor coil or entire contactor with same voltage/spec","2. Re-verify coil voltage after replacement","3. Test startup"],level:"easy"},cn_r_wiring_comp:{type:"result",title:"접촉기 → 압축기 구간 배선 불량",title_en:"Wiring fault between contactor and compressor",causes:["단자 이완","배선 단선","압착 단자 불량"],causes_en:["Terminal loose","Wiring broken","Defective crimp terminal"],steps:["1. 접촉기 출력 → 압축기 단자 구간 배선 점검","2. 각 단자 나사 조임","3. 단선 구간 교체 또는 재배선"],steps_en:["1. Inspect wiring from contactor output to compressor terminals","2. Tighten all terminal screws","3. Replace or rewire broken section"],level:"easy"},cn_r_contactor_contact:{type:"result",title:"접촉기 주접점 소손",title_en:"Contactor main contact burned",causes:["주접점 아크로 인한 소손","잦은 기동으로 접점 마모"],causes_en:["Main contact burned from arcing","Contact wear from frequent starts"],steps:["1. 접촉기 주접점 상태 육안 확인","2. 접점 표면 파임·소손 확인","3. 동일 규격 접촉기 교체"],steps_en:["1. Visually inspect main contact condition","2. Check for pitting or burning on contact surface","3. Replace with same-spec contactor"],level:"easy"},cn_r_capacitor:{type:"result",title:"기동 콘덴서 불량",title_en:"Defective start capacitor",causes:["콘덴서 용량 저하","콘덴서 개방(단선)"],causes_en:["Capacitor capacity degraded","Capacitor open (broken)"],steps:["1. 전원 차단 후 콘덴서 방전","2. 용량계(LCR 미터)로 정확한 용량 측정","3. 정격 ±20% 이상 편차 시 동일 규격(μF, V)으로 교체","4. 교체 후 기동 전류 확인"],steps_en:["1. Cut power and discharge capacitor","2. Measure exact capacity with LCR meter","3. Replace with same spec (μF, V) if deviation exceeds ±20%","4. Check inrush current after replacement"],level:"easy"},cn_r_seized_light:{type:"result",title:"압축기 경미한 고착 (윤활 부족)",title_en:"Minor compressor seizure (insufficient lubrication)",causes:["냉동유 부족으로 인한 마찰 증가","장기 미운전 후 오일 고착"],causes_en:["Increased friction from oil shortage","Oil sticking after long shutdown"],steps:["1. 냉동유 레벨 확인 및 보충","2. 압축기에 극성을 바꿔가며 짧게 기동 시도 (고착 풀기)","3. 이상 소음 없이 기동되면 정상 운전 확인","4. 재발 시 압축기 교체 검토"],steps_en:["1. Check and top up oil level","2. Attempt short starts with reversed polarity to free seized mechanism","3. If starts without abnormal noise, confirm normal operation","4. If recurs, consider compressor replacement"],level:"medium"},cn_r_start_winding:{type:"result",title:"기동 권선 불량 또는 원심 스위치 고장",title_en:"Start winding failure or centrifugal switch fault",causes:["기동 권선 단선 또는 저항 이상","단상 압축기 내부 원심 스위치 고착"],causes_en:["Start winding open or abnormal resistance","Centrifugal switch stuck inside single-phase compressor"],steps:["1. C-S(기동 권선) 저항 측정 및 정상값과 비교","2. 이상 시 압축기 교체","3. 원심 스위치는 압축기 내부 부품 - 교체 불가, 압축기 교체"],steps_en:["1. Measure C-S (start winding) resistance and compare to normal value","2. Replace compressor if abnormal","3. Centrifugal switch is internal — cannot be replaced separately, replace compressor"],level:"hard"},cn_r_comp_3ph_fault:{type:"result",title:"3상 압축기 내부 결함",title_en:"Internal 3-phase compressor fault",causes:["3상 권선 불균형","밸브 기계적 고착"],causes_en:["3-phase winding imbalance","Valve mechanical seizure"],steps:["1. 각 상 권선 저항 측정 (균형 여부)","2. 불균형 시 압축기 교체","3. 고착 의심 시 냉동유 보충 후 재시도"],steps_en:["1. Measure each phase winding resistance (check balance)","2. Replace compressor if unbalanced","3. If seizure suspected, top up oil and retry"],level:"hard"},cn_r_phase_issue:{type:"result",title:"역상 또는 결상 (3상 배선 문제)",title_en:"Phase reversal or phase loss (3-phase wiring issue)",causes:["3상 배선 2선 교차 연결 (역상)","한 상 단선 (결상)"],causes_en:["Two wires of 3-phase wiring crossed (phase reversal)","One phase broken (phase loss)"],steps:["1. 각 상 전압 측정 (R-S, S-T, T-R 각각)","2. 결상 발견 시 해당 상 배선 점검 및 수리","3. 역상 발견 시 두 상 배선 교환 (예: R↔S)","4. 역상 보호 릴레이 설치 검토"],steps_en:["1. Measure each phase voltage (R-S, S-T, T-R)","2. If phase loss: inspect and repair that phase's wiring","3. If phase reversal: swap two phases (e.g. R↔S)","4. Consider installing phase reversal protection relay"],level:"medium",warning:"역상 상태로 압축기 기동 시 즉시 소손",warning_en:"Starting compressor under phase reversal causes immediate burnout"},cn_r_thermal_prot:{type:"result",title:"서멀 프로텍터 동작 (과열 보호)",title_en:"Thermal protector activated (overheat protection)",causes:["압축기 권선 과열","주변 온도 과도하게 높음","냉동유 부족"],causes_en:["Compressor winding overheat","Excessive ambient temperature","Insufficient oil"],steps:["1. 15분 이상 냉각 대기 (서멀 프로텍터 자동 복귀형)","2. 수동 리셋형이면 리셋 버튼 확인 후 누르기","3. 재기동 후 운전 전류 측정","4. 재발 시 과열 원인 조사 (고압, 냉동유, 환기)"],steps_en:["1. Wait at least 15 minutes to cool (auto-reset type)","2. For manual reset type, locate and press reset button","3. Measure operating current after restart","4. If recurs, investigate overheating cause (high pressure, oil, ventilation)"],level:"medium"},cn_r_voltage_unstable:{type:"result",title:"단자 전압 불안정 또는 저전압",title_en:"Unstable or low terminal voltage",causes:["전원 전압 저하 (정격 -10% 이하)","배선 저항 과대로 전압 강하","접촉기 접점 불량"],causes_en:["Supply voltage drop (below rated -10%)","Excessive wiring resistance causing voltage drop","Defective contactor contact"],steps:["1. 압축기 단자 전압을 운전 중 측정","2. 정격 ±10% 이내인지 확인","3. 저전압이면 배선 굵기 및 접촉기 접점 점검","4. 한전 공급 전압 확인"],steps_en:["1. Measure compressor terminal voltage during operation","2. Confirm within ±10% of rated","3. If low voltage: check wiring gauge and contactor contacts","4. Check utility supply voltage"],level:"medium"},cn_r_measure_resistance:{type:"result",title:"압축기 단자간 저항 측정 필요",title_en:"Compressor terminal resistance measurement needed",causes:["점검 미실시"],causes_en:["Inspection not yet performed"],steps:["1. 전원 완전 차단 후 압축기 배선 분리","2. 멀티미터 저항 모드 (Ω)","3. C-S, C-R, S-R 각각 측정 및 기록","4. C-S + C-R = S-R 이 되어야 정상"],steps_en:["1. Fully cut power and disconnect compressor wiring","2. Set multimeter to resistance mode (Ω)","3. Measure and record C-S, C-R, S-R","4. Normal: C-S + C-R = S-R"],level:"easy"},cn_r_winding_fault:{type:"result",title:"압축기 권선 단선 또는 단락",title_en:"Compressor winding open or short circuit",causes:["권선 절연 노후 파괴 후 단락","권선 단선"],causes_en:["Winding short after insulation breakdown","Winding open circuit"],steps:["1. 냉매 완전 회수","2. 오일 산성화 확인","3. 압축기 교체","4. 산성화 오일 있으면 시스템 플러싱 필수","5. 신품 드라이어 교체 후 냉매 재충전"],steps_en:["1. Fully recover refrigerant","2. Test oil for acidity","3. Replace compressor","4. System flushing mandatory if oil is acidic","5. Install new filter-drier and recharge refrigerant"],level:"hard",warning:"산성 오일 방치 시 시스템 전체 오염",warning_en:"Leaving acidic oil will contaminate the entire system"},cn_r_ground_fault:{type:"result",title:"압축기 권선 지락",title_en:"Compressor winding ground fault",causes:["절연 파괴로 권선 → 철심 단락"],causes_en:["Insulation failure causing winding-to-core short"],steps:["1. 냉매 회수","2. 오일 산성화 테스트","3. 압축기 교체","4. 시스템 플러싱 및 드라이어 교체","5. 냉매 재충전"],steps_en:["1. Recover refrigerant","2. Test oil acidity","3. Replace compressor","4. Flush system and replace filter-drier","5. Recharge refrigerant"],level:"hard",warning:"지락 상태 기동 반복 시 화재 위험",warning_en:"Repeatedly starting under ground fault creates fire risk"},cn_r_seized:{type:"result",title:"압축기 내부 기계적 고착",title_en:"Compressor internal mechanical seizure",causes:["냉동유 완전 소진으로 베어링 소손","이물질 유입","장기 미운전 후 고착"],causes_en:["Bearing seized from complete oil loss","Foreign matter ingress","Seizure after long shutdown"],steps:["1. 냉동유 레벨 확인 (소진 여부)","2. 극성 교환 재기동 시도 (경미한 고착)","3. 움직이지 않으면 압축기 교체","4. 오일 부족이 원인이면 재발 방지 대책 수립"],steps_en:["1. Check oil level (is it completely empty?)","2. Attempt restart with reversed polarity (for minor seizure)","3. If still won't turn, replace compressor","4. If oil shortage was the cause, establish preventive measures"],level:"hard"},pc_q1:{question:"압축기는 정상적으로 기동하고 운전 중인가요?",question_en:"Is the compressor starting and running normally?",yes:"pc_q2",no:"pc_r_comp_first"},pc_q2:{question:"증발기에 서리(착상)가 두껍게 끼어 있나요? (손가락 두께 이상)",question_en:"Is there heavy frost buildup on the evaporator? (thicker than a finger)",yes:"pc_q2y",no:"pc_q3"},pc_q2y:{question:"강제 제상 후에도 냉각 불량이 지속되나요?",question_en:"Does poor cooling persist even after forced defrost?",yes:"pc_q3",no:"pc_r_defrost_fix"},pc_q3:{question:"사이트글라스(액면 지시계)에 기포가 보이나요?",question_en:"Are bubbles visible in the sight glass?",yes:"pc_q3y",no:"pc_q4"},pc_q3y:{question:"기포가 간헐적으로 나타났다 사라지나요? (지속적 기포가 아닌)",question_en:"Are bubbles appearing intermittently? (not continuous)",yes:"pc_r_slight_shortage",no:"pc_r_low_ref"},pc_q4:{question:"저압(흡입 압력)이 냉매별 정상 범위보다 낮게 측정되나요?",question_en:"Is suction pressure measuring below the normal range for your refrigerant type?",yes:"pc_q4y",no:"pc_q5"},pc_q4y:{question:"흡입관(증발기 출구)이 과도하게 차갑고 결로가 심한가요?",question_en:"Is the suction line (evaporator outlet) excessively cold with heavy condensation?",yes:"pc_r_txv_closed",no:"pc_q4y_n"},pc_q4y_n:{question:"흡입 스트레이너(필터)를 최근에 점검했나요? 막혀 있지 않나요?",question_en:"Has the suction strainer been checked recently? Is it not clogged?",yes:"pc_r_ref_shortage",no:"pc_r_strainer"},pc_q5:{question:"고압(토출 압력)이 정상보다 높게 측정되나요?",question_en:"Is discharge pressure measuring above normal?",yes:"pc_q5y",no:"pc_q6"},pc_q5y:{question:"응축기 팬이 정상적으로 돌고 있나요?",question_en:"Is the condenser fan running normally?",yes:"pc_q5y_fanok",no:"pc_r_cond_fan"},pc_q5y_fanok:{question:"응축기 핀에 먼지나 이물질이 많이 끼어 있나요?",question_en:"Is there heavy dust or debris accumulated on the condenser fins?",yes:"pc_r_cond_dirty",no:"pc_r_overcharge"},pc_q6:{question:"증발기 팬이 정상적으로 돌고 있나요?",question_en:"Is the evaporator fan running normally?",yes:"pc_q7",no:"pc_r_evap_fan"},pc_q7:{question:"냉동기 사용 연수가 10년 이상인가요?",question_en:"Has the refrigeration unit been in use for 10 years or more?",yes:"pc_r_aged",no:"pc_r_comp_valve"},pc_r_comp_first:{type:"result",title:"압축기 문제 먼저 해결 필요",title_en:"Compressor issue must be resolved first",causes:["압축기 미기동"],causes_en:["Compressor not starting"],steps:["1. '압축기가 안 돌아간다' 진단으로 이동","2. 압축기 문제 해결 후 냉각 불량 재점검"],steps_en:["1. Go to 'Compressor does not start' diagnosis","2. Recheck cooling issue after resolving compressor problem"],level:"medium"},pc_r_defrost_fix:{type:"result",title:"착상 과다 - 제상 계통 점검 필요",title_en:"Excessive frost — defrost system needs inspection",causes:["제상 히터 단선","제상 타이머 설정 불량","도어 패킹 불량"],causes_en:["Defrost heater open circuit","Defrost timer setting error","Door gasket failure"],steps:["1. 제상 타이머 횟수·시간 설정 확인 (1일 3~4회, 25~30분)","2. 제상 히터 저항 측정","3. 도어 패킹 밀착 확인","4. '서리가 너무 많이 낀다' 진단으로 이동하여 상세 점검"],steps_en:["1. Check defrost timer frequency and duration (3-4 times/day, 25-30 min)","2. Measure defrost heater resistance","3. Check door gasket seal","4. Go to 'Excessive frost' diagnosis for detailed inspection"],level:"medium"},pc_r_slight_shortage:{type:"result",title:"냉매 소량 부족 (간헐적 기포)",title_en:"Slight refrigerant shortage (intermittent bubbles)",causes:["미세 누설로 장기간 냉매 감소"],causes_en:["Gradual refrigerant loss from minor leak"],steps:["1. 전체 배관 누설 점검 (전자식 탐지기 또는 비눗물)","2. 누설 부위 수리 후 냉매 소량 보충","3. 충전 후 사이트글라스 기포 소멸 확인"],steps_en:["1. Check all piping for leaks (electronic detector or soapy water)","2. Repair leak then add small amount of refrigerant","3. Confirm bubbles disappear from sight glass after charging"],level:"medium"},pc_r_low_ref:{type:"result",title:"냉매 심각 부족 - 누설 수리 후 재충전",title_en:"Severe refrigerant shortage — repair leak and recharge",causes:["배관 누설 (플레어 이음부, 용접부, 밸브 패킹)"],causes_en:["Piping leak (flare joints, weld points, valve packing)"],steps:["1. 누설 위치 특정 (전자식 탐지기 우선)","2. 누설 부위 수리 (플레어 재작업 또는 용접)","3. 진공 작업 (500미크론 이하)","4. 규정량 충전","5. 1시간 운전 후 재확인"],steps_en:["1. Locate leak (use electronic detector first)","2. Repair leak (re-flare or weld)","3. Evacuate to below 500 microns","4. Charge to specified amount","5. Re-verify after 1 hour of operation"],level:"medium",warning:"누설 수리 없이 냉매만 보충하지 않는다",warning_en:"Never top up refrigerant without repairing the leak"},pc_r_txv_closed:{type:"result",title:"팽창밸브 과도하게 닫힘 (감온통 문제)",title_en:"Expansion valve too closed (sensing bulb issue)",causes:["감온통 흡입관 밀착 불량","감온통 내부 냉매 누설","팽창밸브 필터 막힘"],causes_en:["Sensing bulb not properly attached to suction line","Sensing bulb internal refrigerant leak","Expansion valve filter clogged"],steps:["1. 감온통이 흡입관에 단단히 밀착되어 있는지 확인","2. 감온통 단열 처리 상태 확인","3. 팽창밸브 필터 분해 청소","4. 개도 수동 조정 (시계 반대 방향으로 1~2회전)"],steps_en:["1. Verify sensing bulb is firmly attached to suction line","2. Check insulation wrapping on sensing bulb","3. Disassemble and clean expansion valve filter","4. Manually adjust opening (turn 1-2 turns counterclockwise)"],level:"medium"},pc_r_ref_shortage:{type:"result",title:"냉매 부족 (저압 하강)",title_en:"Refrigerant shortage (low suction pressure)",causes:["냉매 누설 (배관, 밸브, 이음부)"],causes_en:["Refrigerant leak (piping, valves, joints)"],steps:["1. 누설 점검 (비눗물 또는 탐지기)","2. 누설 수리","3. 진공 후 재충전"],steps_en:["1. Check for leaks (soapy water or detector)","2. Repair leak","3. Evacuate and recharge"],level:"medium"},pc_r_strainer:{type:"result",title:"흡입 스트레이너 막힘",title_en:"Suction strainer clogged",causes:["장기간 미청소로 이물질 축적","냉동유 슬러지 막힘"],causes_en:["Long-term buildup of debris","Oil sludge blockage"],steps:["1. 흡입 스트레이너 분해 청소","2. 망 손상 여부 확인","3. 손상 시 교체","4. 청소 후 저압 정상화 확인"],steps_en:["1. Disassemble and clean suction strainer","2. Check mesh for damage","3. Replace if damaged","4. Confirm low-side pressure normalizes after cleaning"],level:"easy"},pc_r_cond_fan:{type:"result",title:"응축기 팬 불량으로 고압 상승",title_en:"High pressure due to condenser fan failure",causes:["팬 모터 불량","팬 캐패시터 불량","팬 블레이드 이물질"],causes_en:["Fan motor failure","Fan capacitor failure","Foreign object in fan blade"],steps:["1. 팬 이물질 제거 후 재시도","2. 팬 모터 전원 확인","3. 캐패시터 용량 측정","4. 불량 부품 교체 후 고압 정상화 확인"],steps_en:["1. Remove foreign objects from fan and retry","2. Check fan motor power supply","3. Measure capacitor capacity","4. Replace faulty parts and confirm high-side pressure normalizes"],level:"easy"},pc_r_cond_dirty:{type:"result",title:"응축기 오염으로 냉각 불량",title_en:"Poor cooling due to fouled condenser",causes:["핀 사이 먼지·이물질 축적으로 열방출 저하"],causes_en:["Reduced heat rejection from dust/debris in fins"],steps:["1. 고압 세척기로 응축기 핀 세척 (반대 방향에서 불어냄)","2. 세척 후 응축 압력 정상화 확인","3. 정기 청소 주기 수립 (월 1회 권장)"],steps_en:["1. Clean condenser fins with high-pressure washer (blow from opposite side)","2. Confirm condensing pressure normalizes after cleaning","3. Establish regular cleaning schedule (monthly recommended)"],level:"easy"},pc_r_overcharge:{type:"result",title:"냉매 과충전으로 고압 상승",title_en:"High pressure due to refrigerant overcharge",causes:["충전량 초과","이전 작업 시 과충전"],causes_en:["Charge amount exceeded","Overcharged during previous service"],steps:["1. 고압 측정값 확인","2. 소량씩 냉매 회수하며 고압 정상 범위 조정","3. 저압도 동시 확인하며 최적값 설정"],steps_en:["1. Check high-side pressure reading","2. Recover refrigerant in small amounts while adjusting to normal high-side range","3. Monitor low-side simultaneously to find optimal charge"],level:"medium"},pc_r_evap_fan:{type:"result",title:"증발기 팬 불량으로 냉기 순환 불량",title_en:"Poor cold air circulation due to evaporator fan failure",causes:["팬 모터 불량","팬 캐패시터 불량","팬 블레이드 손상"],causes_en:["Fan motor failure","Fan capacitor failure","Fan blade damage"],steps:["1. 팬 전원 공급 확인","2. 캐패시터 용량 측정","3. 모터 베어링 유격 확인","4. 불량 부품 교체"],steps_en:["1. Check fan power supply","2. Measure capacitor capacity","3. Check motor bearing play","4. Replace faulty parts"],level:"easy"},pc_r_aged:{type:"result",title:"노후로 인한 냉동 능력 저하",title_en:"Cooling capacity reduction due to aging",causes:["압축기 밸브 마모로 효율 저하","열교환기 오염 누적","냉매 미세 누설 누적"],causes_en:["Efficiency drop from worn compressor valves","Accumulated heat exchanger fouling","Accumulated refrigerant microleaks"],steps:["1. 응축기·증발기 전체 청소","2. 냉매 충전량 재점검 및 누설 확인","3. 운전 전류 및 압력 측정 후 압축기 효율 평가","4. 경제성 검토 후 설비 교체 여부 결정"],steps_en:["1. Thoroughly clean condenser and evaporator","2. Recheck refrigerant charge and inspect for leaks","3. Measure operating current and pressures to evaluate compressor efficiency","4. Evaluate economics and decide whether to replace equipment"],level:"medium"},pc_r_comp_valve:{type:"result",title:"압축기 밸브 효율 저하",title_en:"Reduced compressor valve efficiency",causes:["흡입·토출 밸브 마모 또는 파손","밸브 시트 누설"],causes_en:["Suction/discharge valve wear or damage","Valve seat leakage"],steps:["1. 압축기 정지 후 압력 평형 시간 측정 (정상보다 빠르면 밸브 누설)","2. 운전 전류가 정격 대비 낮으면 압축 효율 저하 확인","3. 압축기 교체 검토"],steps_en:["1. Measure pressure equalization time after stopping (faster than normal = valve leak)","2. If operating current is below rated, compression efficiency is degraded","3. Consider compressor replacement"],level:"hard"},an_q1:{question:"소음이 주로 압축기 본체에서 나오나요?",question_en:"Is the noise primarily coming from the compressor body?",yes:"an_q2",no:"an_q1n"},an_q1n:{question:"소음이 팬(실내기 팬 또는 실외기 팬) 쪽에서 나오나요?",question_en:"Is the noise coming from a fan (indoor or outdoor)?",yes:"an_q1n_fan",no:"an_q1n_other"},an_q1n_fan:{question:"소음이 실외기(응축기) 팬 쪽인가요?",question_en:"Is the noise from the outdoor unit (condenser) fan?",yes:"an_r_cond_fan_noise",no:"an_r_evap_fan_noise"},an_q1n_other:{question:"배관이나 판넬에서 진동·공명음이 나오나요?",question_en:"Is there vibration or resonance noise from piping or panels?",yes:"an_r_pipe_vibration",no:"an_r_other_noise"},an_q2:{question:"소음이 기동 직후(30초 이내)에만 나고 사라지나요?",question_en:"Does the noise occur only right after startup (within 30 seconds) and then stop?",yes:"an_q2y",no:"an_q3"},an_q2y:{question:"소음이 매번 기동할 때마다 반복되나요?",question_en:"Does the noise repeat every time the compressor starts?",yes:"an_r_liquid_start",no:"an_r_liquid_once"},an_q3:{question:"금속이 부딪히는 '딱딱' 또는 '쿵쿵' 소리인가요?",question_en:"Is it a metallic 'clunking' or 'banging' sound?",yes:"an_q3y",no:"an_q4"},an_q3y:{question:"소음이 운전 중에도 계속 나오나요? (기동 시만이 아닌)",question_en:"Does the noise continue during operation? (not just at startup)",yes:"an_r_liquid_slug",no:"an_r_valve_noise"},an_q4:{question:"지속적인 '덜덜' 진동 또는 '윙윙' 소음인가요?",question_en:"Is it a continuous rattling vibration or humming/whining sound?",yes:"an_q4y",no:"an_q5"},an_q4y:{question:"압축기 마운팅(고정) 볼트가 이완되어 있나요?",question_en:"Are the compressor mounting bolts loose?",yes:"an_r_mount_loose",no:"an_q4y_n"},an_q4y_n:{question:"방진고무(방진 패드)가 경화·균열되어 있나요?",question_en:"Is the anti-vibration rubber (pad) hardened or cracked?",yes:"an_r_rubber",no:"an_r_oil_noise"},an_q5:{question:"'삐~' 또는 '끽끽' 하는 고음이 나오나요?",question_en:"Is there a high-pitched squealing or squeaking sound?",yes:"an_r_bearing",no:"an_r_valve_noise2"},an_r_liquid_start:{type:"result",title:"기동 시 액압축 (크랭크케이스 히터 부재)",title_en:"Liquid slugging at startup (no crankcase heater)",causes:["정지 중 냉매 액체가 크랭크케이스로 역류","크랭크케이스 히터 미설치 또는 불량"],causes_en:["Liquid refrigerant migrating to crankcase during shutdown","No crankcase heater or heater defective"],steps:["1. 크랭크케이스 히터 설치 여부 확인","2. 히터 미설치 시 설치 권장","3. 히터 설치 후 기동 전 30분 예열 후 기동","4. 팽창밸브 과열도 5~10℃ 확인"],steps_en:["1. Check if crankcase heater is installed","2. Install heater if absent (recommended)","3. After installation, preheat 30 minutes before starting","4. Verify expansion valve superheat of 5–10°C"],level:"medium"},an_r_liquid_once:{type:"result",title:"일시적 액압축 (잔류 냉매)",title_en:"Temporary liquid slugging (residual refrigerant)",causes:["이전 정지 직후 재기동으로 잔류 액체 흡입"],causes_en:["Residual liquid sucked in from restarting immediately after last shutdown"],steps:["1. 정지 후 최소 3분 경과 후 재기동 (압력 평형 대기)","2. 소음 재발 시 크랭크케이스 히터 설치 검토"],steps_en:["1. Wait at least 3 minutes after shutdown before restarting (allow pressure equalization)","2. If noise recurs, consider installing crankcase heater"],level:"easy"},an_r_liquid_slug:{type:"result",title:"액압축 진행 중 - 즉시 운전 중단",title_en:"Liquid slugging in progress — STOP IMMEDIATELY",causes:["팽창밸브 개도 과다","냉매 과충전","흡입관 액 고임"],causes_en:["Expansion valve over-opened","Refrigerant overcharge","Liquid pooling in suction line"],steps:["1. 즉시 운전 중단","2. 흡입 과열도 측정 (5℃ 미만이면 액압축)","3. 팽창밸브 개도 조정 (1~2회전 조임)","4. 냉매 충전량 확인 및 과충전 시 회수","5. 압축기 내부 손상 여부 점검 후 재기동"],steps_en:["1. Stop operation immediately","2. Measure suction superheat (below 5°C confirms slugging)","3. Adjust expansion valve (close 1–2 turns)","4. Check refrigerant charge; recover if overcharged","5. Inspect compressor for internal damage before restart"],level:"hard",warning:"액압축 지속 시 압축기 밸브 파손 - 즉시 정지",warning_en:"Continued slugging destroys compressor valves — stop immediately"},an_r_valve_noise:{type:"result",title:"압축기 밸브 손상 의심",title_en:"Suspected compressor valve damage",causes:["액압축으로 인한 밸브 파손","밸브 노후 마모"],causes_en:["Valve damage from liquid slugging","Valve wear with age"],steps:["1. 운전 전류 측정 (정격보다 낮으면 밸브 효율 저하)","2. 토출 온도 측정 (비정상적으로 낮으면 밸브 누설)","3. 압축기 교체 검토"],steps_en:["1. Measure operating current (below rated = reduced valve efficiency)","2. Measure discharge temperature (abnormally low = valve leaking)","3. Consider compressor replacement"],level:"hard"},an_r_mount_loose:{type:"result",title:"마운팅 볼트 이완",title_en:"Loose mounting bolts",causes:["진동으로 인한 볼트 자연 이완"],causes_en:["Natural bolt loosening from vibration"],steps:["1. 압축기 마운팅 볼트 4개소 토크 렌치로 조임","2. 조임 후 소음 재확인","3. 재발 방지를 위해 록타이트 적용 검토"],steps_en:["1. Tighten all 4 compressor mounting bolts with torque wrench","2. Re-check noise after tightening","3. Consider applying Loctite to prevent recurrence"],level:"easy"},an_r_rubber:{type:"result",title:"방진고무 노후 교체 필요",title_en:"Anti-vibration rubber needs replacement",causes:["방진고무 경화·균열로 진동 흡수 불가"],causes_en:["Anti-vibration rubber hardened/cracked, can no longer absorb vibration"],steps:["1. 기존 방진고무 분리","2. 동일 규격 방진고무로 교체","3. 교체 후 진동 재확인"],steps_en:["1. Remove existing anti-vibration rubber","2. Replace with same-spec rubber","3. Re-check vibration after replacement"],level:"easy"},an_r_oil_noise:{type:"result",title:"냉동유 부족으로 인한 소음",title_en:"Noise from insufficient refrigeration oil",causes:["냉동유 레벨 저하로 베어링 윤활 불량"],causes_en:["Bearing lubrication failure from low oil level"],steps:["1. 크랭크케이스 유리관에서 오일 레벨 확인","2. 부족 시 적정 냉동유 보충 (동일 종류 사용)","3. 보충 후 소음 개선 여부 확인","4. 오일 부족 원인 파악 (오일 포밍, 누설)"],steps_en:["1. Check oil level in crankcase sight glass","2. Top up with same-type refrigeration oil if low","3. Confirm noise improves after top-up","4. Identify cause of oil loss (foaming, leakage)"],level:"medium"},an_r_bearing:{type:"result",title:"압축기 베어링 마모",title_en:"Compressor bearing wear",causes:["장기 운전으로 베어링 마모","냉동유 오염으로 인한 마모 가속"],causes_en:["Bearing wear from long-term operation","Accelerated wear from contaminated oil"],steps:["1. 운전 중 소음 위치 정확히 특정","2. 냉동유 오염 여부 확인 (색상 변화, 금속 분말)","3. 압축기 교체 검토 (베어링은 내부 부품)"],steps_en:["1. Precisely locate noise during operation","2. Check oil contamination (color change, metal particles)","3. Consider compressor replacement (bearings are internal components)"],level:"hard"},an_r_valve_noise2:{type:"result",title:"밸브 진동 소음",title_en:"Valve vibration noise",causes:["흡입·토출 밸브 마모로 인한 진동","밸브 스프링 장력 저하"],causes_en:["Vibration from worn suction/discharge valves","Reduced valve spring tension"],steps:["1. 운전 전류 및 압력 데이터 수집","2. 압축기 효율 저하 여부 판단","3. 교체 기준 도달 시 압축기 교체"],steps_en:["1. Collect operating current and pressure data","2. Assess whether compressor efficiency has degraded","3. Replace compressor when replacement criteria are met"],level:"medium"},an_r_cond_fan_noise:{type:"result",title:"응축기 팬 소음",title_en:"Condenser fan noise",causes:["팬 블레이드 이물질 접촉","베어링 마모","블레이드 균열·변형","모터 볼트 이완"],causes_en:["Foreign object contacting blade","Bearing wear","Blade crack/deformation","Motor bolt loose"],steps:["1. 전원 차단 후 팬 이물질 제거","2. 블레이드 균열·변형 육안 확인","3. 모터 베어링 유격 확인","4. 볼트 조임","5. 베어링 불량 시 모터 교체"],steps_en:["1. Cut power and remove foreign objects","2. Visually check blade for cracks/deformation","3. Check motor bearing play","4. Tighten bolts","5. Replace motor if bearing is faulty"],level:"easy"},an_r_evap_fan_noise:{type:"result",title:"증발기 팬 소음",title_en:"Evaporator fan noise",causes:["얼음이 팬 블레이드에 접촉","베어링 마모","팬 블레이드 손상"],causes_en:["Ice contacting fan blade","Bearing wear","Fan blade damage"],steps:["1. 강제 제상 후 얼음 제거","2. 팬 블레이드 상태 점검","3. 모터 베어링 확인","4. 불량 시 교체"],steps_en:["1. Remove ice with forced defrost","2. Inspect fan blade condition","3. Check motor bearings","4. Replace if faulty"],level:"easy"},an_r_pipe_vibration:{type:"result",title:"배관·판넬 진동 소음",title_en:"Pipe/panel vibration noise",causes:["배관 지지대 이완","판넬 볼트 이완으로 공명","플렉시블 조인트 노후"],causes_en:["Loose pipe supports","Panel resonance from loose bolts","Aged flexible joint"],steps:["1. 배관 지지대 전체 점검 및 조임","2. 판넬 볼트 전체 조임","3. 플렉시블 조인트 균열·누설 확인","4. 손으로 배관을 잡아 진동 위치 특정"],steps_en:["1. Inspect and tighten all pipe supports","2. Tighten all panel bolts","3. Check flexible joints for cracks/leaks","4. Hold pipes by hand to locate vibration source"],level:"easy"},an_r_other_noise:{type:"result",title:"기타 소음 - 추가 확인 필요",title_en:"Other noise — further investigation needed",causes:["팽창밸브 흐름 소음","솔레노이드 밸브 개폐음","배관 내 냉매 흐름음"],causes_en:["Expansion valve flow noise","Solenoid valve switching sound","Refrigerant flow sound in piping"],steps:["1. 소음 위치를 청진기 또는 금속 봉으로 정확히 특정","2. 팽창밸브 주변 확인 (거품 또는 흐름음)","3. 솔레노이드 밸브 동작음과 비교","4. 정상 범위의 소음인지 판단"],steps_en:["1. Precisely locate noise using a stethoscope or metal rod","2. Check around expansion valve (bubbling or flow sound)","3. Compare with solenoid valve switching sound","4. Determine whether it is within normal range"],level:"medium"},bt_q1:{question:"차단기를 올리면 즉시(2초 이내) 다시 내려가나요?",question_en:"Does the breaker trip again immediately (within 2 seconds) when reset?",yes:"bt_q1y",no:"bt_q2"},bt_q1y:{question:"누전 차단기(ELB/ELCB)가 트립되고 있나요? (누전 차단기인지 확인)",question_en:"Is it an earth leakage breaker (ELCB) that is tripping?",yes:"bt_q1y_elcb",no:"bt_q1y_mccb"},bt_q1y_elcb:{question:"압축기를 분리했을 때 누전 차단기가 동작하지 않나요?",question_en:"Does the ELCB stop tripping when the compressor is disconnected?",yes:"bt_r_comp_ground2",no:"bt_q1y_elcb_n"},bt_q1y_elcb_n:{question:"팬 모터를 분리했을 때 누전 차단기가 동작하지 않나요?",question_en:"Does the ELCB stop tripping when the fan motor is disconnected?",yes:"bt_r_fan_ground",no:"bt_r_wiring_ground2"},bt_q1y_mccb:{question:"모든 부하를 분리한 후에도 차단기가 트립되나요?",question_en:"Does the breaker still trip after disconnecting all loads?",yes:"bt_r_wiring_short2",no:"bt_q1y_mccb_load"},bt_q1y_mccb_load:{question:"압축기만 연결 시 트립되나요?",question_en:"Does it trip when only the compressor is connected?",yes:"bt_r_comp_short2",no:"bt_r_other_short"},bt_q2:{question:"차단기가 기동 후 수십 초~수 분 사이에 트립되나요?",question_en:"Does the breaker trip tens of seconds to several minutes after startup?",yes:"bt_q2y",no:"bt_q3"},bt_q2y:{question:"클램프미터로 측정한 운전 전류가 차단기 정격 전류를 초과하나요?",question_en:"Does the measured operating current (clamp meter) exceed the breaker's rated current?",yes:"bt_q2y_oc",no:"bt_r_breaker_old2"},bt_q2y_oc:{question:"고압(토출 압력)이 정상보다 높게 측정되나요?",question_en:"Is discharge pressure measuring above normal?",yes:"bt_r_oc_hp",no:"bt_q2y_oc_n"},bt_q2y_oc_n:{question:"기동 콘덴서 용량이 부족하지 않나요? (단상 압축기 해당)",question_en:"Is the start capacitor capacity insufficient? (for single-phase compressors)",yes:"bt_r_oc_cap",no:"bt_r_oc_comp"},bt_q3:{question:"차단기가 하루에 1회 정도 또는 장시간 운전 후 트립되나요?",question_en:"Does the breaker trip about once a day or after long operation periods?",yes:"bt_r_thermal_trip",no:"bt_r_breaker_capacity"},bt_r_comp_ground2:{type:"result",title:"압축기 권선 지락 (누전)",title_en:"Compressor winding ground fault (earth leakage)",causes:["압축기 권선 절연 파괴 → 케이스 지락"],causes_en:["Compressor winding insulation breakdown → casing ground fault"],steps:["1. 압축기 절연저항 측정 (1MΩ 미만 확인)","2. 냉매 회수 후 압축기 교체","3. 시스템 플러싱 및 드라이어 교체","4. 재충전 후 절연저항 재측정"],steps_en:["1. Measure compressor insulation resistance (confirm below 1MΩ)","2. Recover refrigerant and replace compressor","3. Flush system and replace filter-drier","4. After recharge, re-measure insulation resistance"],level:"hard",warning:"지락 상태 운전 반복 시 화재 위험",warning_en:"Repeated operation under ground fault creates fire risk"},bt_r_fan_ground:{type:"result",title:"팬 모터 지락 (누전)",title_en:"Fan motor ground fault (earth leakage)",causes:["팬 모터 권선 절연 저하","수분 침투로 인한 지락"],causes_en:["Fan motor winding insulation degraded","Ground fault from moisture ingress"],steps:["1. 팬 모터 절연저항 측정","2. 1MΩ 미만 확인 시 팬 모터 교체","3. 수분 침투 경로 차단"],steps_en:["1. Measure fan motor insulation resistance","2. Replace fan motor if below 1MΩ","3. Block moisture ingress path"],level:"medium"},bt_r_wiring_ground2:{type:"result",title:"배선 지락",title_en:"Wiring ground fault",causes:["배선 피복 손상 후 지락","단자대 수분 침투"],causes_en:["Wiring ground fault from insulation damage","Moisture in terminal block"],steps:["1. 각 부하 순차 분리하며 누전 발생 부하 특정","2. 해당 배선 절연저항 측정","3. 손상 구간 교체","4. 단자대 수분 확인 및 건조"],steps_en:["1. Disconnect loads one by one to identify source of earth leakage","2. Measure insulation resistance of that wiring","3. Replace damaged section","4. Check terminal block for moisture and dry"],level:"medium"},bt_r_wiring_short2:{type:"result",title:"배선 자체 단락",title_en:"Wiring short circuit",causes:["피복 파손으로 선간 단락","습기·쥐 피해 등"],causes_en:["Wire-to-wire short from insulation damage","Moisture or rodent damage"],steps:["1. 전체 배선 절연저항 측정","2. 손상 구간 특정 후 교체","3. 원인(습기, 기계적 손상) 제거"],steps_en:["1. Measure insulation resistance of all wiring","2. Identify and replace damaged sections","3. Eliminate cause (moisture, mechanical damage)"],level:"hard"},bt_r_comp_short2:{type:"result",title:"압축기 권선 단락",title_en:"Compressor winding short circuit",causes:["권선 절연 파괴 후 선간 단락"],causes_en:["Inter-winding short after insulation failure"],steps:["1. 압축기 단자간 저항 측정 (0Ω 구간 확인)","2. 냉매 회수 후 교체","3. 시스템 플러싱 필수"],steps_en:["1. Measure inter-terminal resistance (confirm 0Ω)","2. Recover refrigerant and replace","3. System flushing mandatory"],level:"hard"},bt_r_other_short:{type:"result",title:"기타 부하 단락",title_en:"Short circuit in other load",causes:["팬 모터, 히터, 컨트롤러 등 단락"],causes_en:["Short circuit in fan motor, heater, controller, etc."],steps:["1. 각 부하 하나씩 연결하며 트립 부하 특정","2. 해당 부품 절연저항 측정","3. 불량 부품 교체"],steps_en:["1. Connect loads one by one to identify which causes the trip","2. Measure insulation resistance of that component","3. Replace faulty component"],level:"medium"},bt_r_breaker_old2:{type:"result",title:"차단기 노후 불량",title_en:"Aged/defective circuit breaker",causes:["10년 이상 노후로 특성 열화"],causes_en:["Degraded characteristics after 10+ years"],steps:["1. 차단기 제조년도 확인","2. 동일 규격 신품으로 교체","3. 교체 후 기동 테스트"],steps_en:["1. Check breaker manufacture date","2. Replace with same-spec new unit","3. Test startup after replacement"],level:"easy"},bt_r_oc_hp:{type:"result",title:"고압 상승으로 과전류",title_en:"Overcurrent from high discharge pressure",causes:["응축기 오염","냉매 과충전","응축기 팬 불량"],causes_en:["Condenser fouling","Refrigerant overcharge","Condenser fan failure"],steps:["1. 응축기 세척","2. 팬 동작 확인","3. 냉매 충전량 조정","4. 원인 해결 후 운전 전류 재측정"],steps_en:["1. Clean condenser","2. Check fan operation","3. Adjust refrigerant charge","4. Re-measure current after resolving cause"],level:"medium"},bt_r_oc_cap:{type:"result",title:"기동 콘덴서 불량으로 과전류",title_en:"Overcurrent from defective start capacitor",causes:["콘덴서 용량 저하로 기동 시 전류 지속"],causes_en:["Extended inrush current from reduced capacitor capacity"],steps:["1. 콘덴서 용량 측정 후 교체","2. 교체 후 기동 전류 재측정"],steps_en:["1. Measure and replace capacitor","2. Re-measure inrush current after replacement"],level:"easy"},bt_r_oc_comp:{type:"result",title:"압축기 자체 과전류",title_en:"Compressor itself drawing excessive current",causes:["내부 마찰 증가","밸브 마모로 효율 저하","냉동유 부족"],causes_en:["Increased internal friction","Efficiency drop from valve wear","Insufficient oil"],steps:["1. 냉동유 레벨 확인","2. 운전 전류 정밀 측정·기록","3. 정격 대비 20% 이상 초과 시 압축기 교체 검토"],steps_en:["1. Check oil level","2. Precisely measure and record operating current","3. If exceeding rated by 20%+, consider compressor replacement"],level:"hard"},bt_r_thermal_trip:{type:"result",title:"열동형 차단기 열 누적 트립",title_en:"Thermal-magnetic breaker heat accumulation trip",causes:["장시간 연속운전으로 차단기 열 누적","주변 온도 높은 판넬에 설치된 차단기"],causes_en:["Breaker heat accumulation from continuous long operation","Breaker installed in high-temperature panel"],steps:["1. 차단기 주변 온도 확인 (40℃ 이하 권장)","2. 판넬 환기 개선","3. 차단기 용량 10~20% 상향 선정 검토","4. 인버터 방식 전환 검토 (기동 전류 저감)"],steps_en:["1. Check temperature around breaker (40°C or below recommended)","2. Improve panel ventilation","3. Consider selecting breaker with 10-20% higher capacity","4. Consider switching to inverter drive (reduces inrush current)"],level:"medium"},bt_r_breaker_capacity:{type:"result",title:"차단기 용량 재검토 필요",title_en:"Circuit breaker capacity needs re-evaluation",causes:["부하 증가 후 차단기 미교체","선정 기준 오류"],causes_en:["Breaker not upgraded after load increase","Selection criteria error"],steps:["1. 최대 운전 전류 정밀 측정","2. 적정 용량 = 최대 전류 × 1.25~1.5","3. 적정 용량 차단기로 교체"],steps_en:["1. Precisely measure maximum operating current","2. Appropriate capacity = max current × 1.25–1.5","3. Replace with properly rated breaker"],level:"easy"},hf_q1:{question:"자동 제상(디프로스트) 기능이 설정되어 있고 작동하고 있나요?",question_en:"Is the automatic defrost function set and operating?",yes:"hf_q2",no:"hf_q1n"},hf_q1n:{question:"제상 타이머(또는 제상 설정)가 아예 꺼져 있나요?",question_en:"Is the defrost timer (or defrost setting) completely disabled?",yes:"hf_r_defrost_off",no:"hf_q1n_n"},hf_q1n_n:{question:"컨트롤러에서 제상 모드 진입 신호가 나오고 있나요?",question_en:"Is the controller sending a signal to enter defrost mode?",yes:"hf_q1n_n_y",no:"hf_r_controller_defrost"},hf_q1n_n_y:{question:"제상 히터에 전원이 인가되고 있나요? (멀티미터 전압 측정)",question_en:"Is power being applied to the defrost heater? (check with multimeter)",yes:"hf_q1n_n_y_pwr",no:"hf_r_heater_relay"},hf_q1n_n_y_pwr:{question:"제상 히터 저항이 정상인가요? (단선 없음, 정격값 근처)",question_en:"Is the defrost heater resistance normal? (no open circuit, near rated value)",yes:"hf_r_drain_block",no:"hf_r_heater_open"},hf_q2:{question:"강제 제상 시 서리가 완전히 녹나요?",question_en:"Does frost completely melt during forced defrost?",yes:"hf_q3",no:"hf_q2n"},hf_q2n:{question:"제상 히터 전류를 측정했을 때 정격보다 낮지 않나요?",question_en:"Is the measured defrost heater current not lower than rated?",yes:"hf_r_defrost_short_time",no:"hf_r_heater_partial"},hf_q3:{question:"제상 후 시간이 지나면 다시 착상이 빠르게 생기나요?",question_en:"Does frost re-accumulate quickly after defrost completes?",yes:"hf_q4",no:"hf_r_defrost_interval"},hf_q4:{question:"냉동실 도어(문) 패킹(고무 씰)이 손상되거나 밀착이 불량한가요?",question_en:"Is the door gasket (rubber seal) damaged or not sealing properly?",yes:"hf_r_gasket2",no:"hf_q5"},hf_q5:{question:"냉동실 문이 자주 열리거나 오랫동안 열려 있는 환경인가요?",question_en:"Is the freezer door frequently opened or left open for long periods?",yes:"hf_r_door_open",no:"hf_q6"},hf_q6:{question:"냉매가 과충전되어 있지 않나요? (저압이 너무 낮음)",question_en:"Is the refrigerant not overcharged? (suction pressure too low)",yes:"hf_r_overcharge_frost",no:"hf_r_humid_env"},hf_r_defrost_off:{type:"result",title:"제상 기능 비활성화",title_en:"Defrost function disabled",causes:["실수로 제상 타이머 OFF","설치 시 설정 누락"],causes_en:["Defrost timer accidentally turned off","Setting omitted during installation"],steps:["1. 컨트롤러에서 제상 타이머 설정 (1일 3~4회, 25~30분)","2. 강제 제상으로 기존 서리 완전 제거 후 정상 운전"],steps_en:["1. Set defrost timer on controller (3-4 times/day, 25-30 min)","2. Run forced defrost to fully remove existing frost, then resume normal operation"],level:"easy"},hf_r_controller_defrost:{type:"result",title:"컨트롤러 제상 신호 미출력",title_en:"Controller not outputting defrost signal",causes:["제상 출력 릴레이 불량","컨트롤러 PCB 불량"],causes_en:["Defrost output relay failure","Controller PCB failure"],steps:["1. 컨트롤러 제상 출력 단자 전압 확인","2. 출력 없으면 컨트롤러 교체"],steps_en:["1. Check voltage at controller defrost output terminal","2. If no output, replace controller"],level:"medium"},hf_r_heater_relay:{type:"result",title:"제상 히터 릴레이 또는 배선 불량",title_en:"Defrost heater relay or wiring failure",causes:["히터 공급 릴레이 불량","히터 배선 단선"],causes_en:["Heater supply relay failure","Heater wiring open circuit"],steps:["1. 히터 전원 공급 릴레이 동작 확인","2. 히터 배선 단선 점검","3. 불량 부품 교체"],steps_en:["1. Check heater power supply relay operation","2. Inspect heater wiring for open circuit","3. Replace faulty components"],level:"medium"},hf_r_heater_open:{type:"result",title:"제상 히터 단선",title_en:"Defrost heater open circuit",causes:["히터 발열선 단선 (노후, 과열)"],causes_en:["Heater element broken (aged, overheated)"],steps:["1. 동일 규격 제상 히터로 교체","2. 제상 종료 센서(온도퓨즈) 함께 점검","3. 교체 후 강제 제상 테스트"],steps_en:["1. Replace with same-spec defrost heater","2. Also inspect defrost termination sensor (thermal fuse)","3. Run forced defrost test after replacement"],level:"easy"},hf_r_drain_block:{type:"result",title:"드레인(배수구) 막힘",title_en:"Drain blocked",causes:["제상수 배수구 얼음으로 막힘","이물질 퇴적"],causes_en:["Defrost water drain blocked by ice","Debris accumulation"],steps:["1. 배수구 및 배수호스 점검","2. 얼음 막힘 시 온수로 녹임","3. 배수호스 경로 역경사 없는지 확인"],steps_en:["1. Inspect drain hole and drain hose","2. Melt ice blockage with warm water","3. Verify drain hose has no upward slope"],level:"easy"},hf_r_defrost_short_time:{type:"result",title:"제상 시간 부족",title_en:"Insufficient defrost duration",causes:["제상 시간이 너무 짧게 설정됨","제상 종료 센서가 너무 빠르게 차단"],causes_en:["Defrost duration set too short","Defrost termination sensor cutting off too early"],steps:["1. 제상 시간 연장 (20분 → 30~40분)","2. 제상 종료 센서(온도퓨즈) 설정 온도 확인 (보통 10~15℃)","3. 조정 후 착상 감소 확인"],steps_en:["1. Extend defrost duration (20 min → 30-40 min)","2. Check defrost termination sensor setpoint temperature (typically 10-15°C)","3. Confirm frost reduction after adjustment"],level:"easy"},hf_r_heater_partial:{type:"result",title:"제상 히터 부분 단선 (용량 부족)",title_en:"Partial defrost heater open (insufficient capacity)",causes:["히터 일부 소손으로 저항 증가","히터 노후"],causes_en:["Partial heater burnout increasing resistance","Aged heater"],steps:["1. 히터 저항 측정 (정격값 대비 높으면 부분 단선)","2. 히터 전체 교체","3. 교체 후 전류 측정으로 정상 확인"],steps_en:["1. Measure heater resistance (above rated = partial open)","2. Replace entire heater","3. Measure current after replacement to confirm normal"],level:"medium"},hf_r_defrost_interval:{type:"result",title:"제상 주기 조정 필요",title_en:"Defrost interval needs adjustment",causes:["제상 횟수 부족","운전 환경 대비 제상 설정 부족"],causes_en:["Insufficient defrost frequency","Defrost settings inadequate for operating environment"],steps:["1. 제상 횟수 증가 (예: 2회 → 4회/일)","2. 습도 높은 환경이면 횟수 추가 증가","3. 2일 관찰 후 착상 상태 재확인"],steps_en:["1. Increase defrost frequency (e.g. 2 → 4 times/day)","2. Further increase frequency for high-humidity environments","3. Re-check frost after 2-day observation"],level:"easy"},hf_r_gasket2:{type:"result",title:"도어 패킹 불량 - 외부 습기 유입",title_en:"Defective door gasket — external moisture ingress",causes:["패킹 노후·경화","도어 힌지 처짐으로 밀착 불량"],causes_en:["Aged/hardened gasket","Door sag from hinge wear causing poor seal"],steps:["1. 종이 끼우기 테스트로 밀착 확인 (빠지면 불량)","2. 패킹 전체 교체","3. 힌지 조정 또는 교체","4. 교체 후 강제 제상으로 기존 서리 완전 제거"],steps_en:["1. Paper test to check seal (if it slides out easily, gasket is faulty)","2. Replace entire gasket","3. Adjust or replace hinges","4. After replacement, run forced defrost to fully remove existing frost"],level:"easy"},hf_r_door_open:{type:"result",title:"도어 개방 빈도 과다 - 운용 개선 필요",title_en:"Door opened too frequently — operational improvement needed",causes:["작업 특성상 잦은 도어 개방","도어 자동 닫힘 장치 불량"],causes_en:["Frequent door opening due to work requirements","Door auto-close mechanism failure"],steps:["1. 도어 자동 닫힘 장치 확인 및 수리","2. 에어 커튼 설치 검토","3. 제상 횟수 증가로 보완"],steps_en:["1. Check and repair door auto-close mechanism","2. Consider installing air curtain","3. Compensate by increasing defrost frequency"],level:"easy"},hf_r_overcharge_frost:{type:"result",title:"냉매 과충전으로 착상 과다",title_en:"Excessive frost from refrigerant overcharge",causes:["냉매 과충전으로 증발 온도 과도하게 낮아짐"],causes_en:["Excessively low evaporation temperature from overcharge"],steps:["1. 고·저압 동시 측정","2. 저압이 정상보다 낮으면 과충전 의심","3. 소량 냉매 회수 후 압력 재확인"],steps_en:["1. Measure both high and low side pressures","2. If low-side is below normal, suspect overcharge","3. Recover small amount of refrigerant and re-verify pressures"],level:"medium"},hf_r_humid_env:{type:"result",title:"고습도 환경으로 착상 과다",title_en:"Excessive frost from high-humidity environment",causes:["설치 환경 습도가 높음 (해안가, 지하, 주방 인근)"],causes_en:["High-humidity installation environment (coastal, basement, near kitchen)"],steps:["1. 제상 횟수·시간 추가 증가","2. 제상 히터 용량 증설 검토","3. 냉동실 인근 환기 개선","4. 도어 씰 강화"],steps_en:["1. Further increase defrost frequency and duration","2. Consider increasing defrost heater capacity","3. Improve ventilation near freezer","4. Reinforce door seal"],level:"medium"},sc_q1:{question:"압축기가 5분 이내에 자꾸 껐다 켜지고 있나요?",question_en:"Is the compressor cycling on and off within 5 minutes?",yes:"sc_q2",no:"sc_q1n"},sc_q1n:{question:"10~20분 주기로 껐다 켜지나요? (비교적 긴 주기)",question_en:"Is it cycling off and on every 10-20 minutes? (relatively long interval)",yes:"sc_r_normal_cycle",no:"sc_r_check_setpoint"},sc_q2:{question:"압축기가 멈출 때 고압 스위치 동작 표시가 있나요?",question_en:"Is there a high pressure switch indicator when the compressor stops?",yes:"sc_r_sc_hp",no:"sc_q3"},sc_q3:{question:"압축기가 멈출 때 저압 스위치 동작 표시가 있나요?",question_en:"Is there a low pressure switch indicator when the compressor stops?",yes:"sc_r_sc_lp",no:"sc_q4"},sc_q4:{question:"압축기가 멈출 때 과부하(과열) 릴레이가 동작하나요?",question_en:"Does the overload relay trip when the compressor stops?",yes:"sc_r_sc_overload",no:"sc_q5"},sc_q5:{question:"온도 설정값이 현재 온도보다 조금만 낮게 설정되어 있나요?",question_en:"Is the temperature setpoint set only slightly below the current temperature?",yes:"sc_r_sc_setpoint",no:"sc_r_sc_controller"},sc_r_normal_cycle:{type:"result",title:"정상 운전 사이클",title_en:"Normal operating cycle",causes:["설계된 정상 ON/OFF 사이클"],causes_en:["Normal designed ON/OFF cycle"],steps:["1. 정상 운전 사이클임을 확인","2. 냉각 온도가 설정값에 도달하면 정지 → 온도 상승하면 재기동은 정상","3. 주기가 너무 잦으면 온도 설정값 재검토"],steps_en:["1. Confirm this is a normal operating cycle","2. Compressor stops when setpoint is reached, restarts when temp rises — this is normal","3. If cycling frequency is too high, re-evaluate temperature setpoint"],level:"easy"},sc_r_check_setpoint:{type:"result",title:"온도 설정값 및 센서 점검",title_en:"Check temperature setpoint and sensor",causes:["온도 편차 설정(히스테리시스) 너무 작음","센서 오감지"],causes_en:["Temperature differential (hysteresis) setting too small","Sensor misreading"],steps:["1. 온도 편차(히스테리시스) 설정값 확인 및 확대 (예: 1℃ → 3℃)","2. 온도 센서 저항값 측정으로 정상 여부 확인"],steps_en:["1. Check and increase temperature hysteresis setting (e.g. 1°C → 3°C)","2. Measure temperature sensor resistance to verify normal operation"],level:"easy"},sc_r_sc_hp:{type:"result",title:"고압 트립으로 인한 단속운전",title_en:"Short cycling from high pressure trip",causes:["응축기 오염","응축기 팬 불량","냉매 과충전","불응축 가스"],causes_en:["Condenser fouling","Condenser fan failure","Refrigerant overcharge","Non-condensable gas"],steps:["1. 응축기 팬 동작 확인","2. 응축기 세척","3. 냉매 충전량 조정","4. 원인 해결 후 고압 스위치 리셋","5. 단속운전 재발 여부 확인"],steps_en:["1. Verify condenser fan operation","2. Clean condenser","3. Adjust refrigerant charge","4. Reset high pressure switch after resolving cause","5. Monitor for recurrence of short cycling"],level:"medium"},sc_r_sc_lp:{type:"result",title:"저압 트립으로 인한 단속운전",title_en:"Short cycling from low pressure trip",causes:["냉매 부족","팽창밸브 닫힘","흡입 스트레이너 막힘"],causes_en:["Refrigerant shortage","Expansion valve closed","Suction strainer clogged"],steps:["1. 냉매 누설 점검","2. 팽창밸브 감온통 밀착 확인","3. 흡입 스트레이너 청소","4. 원인 해결 후 저압 스위치 리셋"],steps_en:["1. Inspect for refrigerant leaks","2. Verify expansion valve sensing bulb contact","3. Clean suction strainer","4. Reset low pressure switch after resolving cause"],level:"medium"},sc_r_sc_overload:{type:"result",title:"과부하 트립으로 인한 단속운전",title_en:"Short cycling from overload trip",causes:["과전류 (고압, 기동콘덴서)","냉동유 부족"],causes_en:["Overcurrent (high pressure, start capacitor)","Insufficient oil"],steps:["1. 과부하 원인 분석 ('전기가 자꾸 끊긴다' 진단 참조)","2. 원인 해결 후 재기동","3. 단속 재발 여부 모니터링"],steps_en:["1. Analyze overload cause (refer to 'breaker tripping' diagnosis)","2. Restart after resolving cause","3. Monitor for recurrence"],level:"medium"},sc_r_sc_setpoint:{type:"result",title:"온도 설정값 문제로 단속운전",title_en:"Short cycling from temperature setpoint issue",causes:["설정 온도 편차(히스테리시스)가 너무 좁음"],causes_en:["Temperature setpoint differential (hysteresis) too narrow"],steps:["1. 히스테리시스 설정을 2~3℃로 확대","2. 또는 설정 온도를 현재 온도보다 충분히 낮게 조정"],steps_en:["1. Widen hysteresis setting to 2-3°C","2. Or set temperature setpoint sufficiently below current temperature"],level:"easy"},sc_r_sc_controller:{type:"result",title:"컨트롤러 오작동으로 단속운전",title_en:"Short cycling from controller malfunction",causes:["컨트롤러 출력 릴레이 접점 불량","컨트롤러 오류 코드 발생"],causes_en:["Controller output relay contact failure","Controller error code occurring"],steps:["1. 컨트롤러 오류 코드 확인","2. 컨트롤러 초기화(리셋) 시도","3. 재발 시 컨트롤러 교체"],steps_en:["1. Check controller error codes","2. Attempt controller reset/initialization","3. Replace controller if problem recurs"],level:"medium"},hp_q1:{question:"고압계를 연결해서 실제 고압 수치를 확인했나요?",question_en:"Have you connected a gauge and verified the actual high-side pressure reading?",yes:"hp_q2",no:"hp_r_measure_first"},hp_q2:{question:"응축기 팬이 정상적으로 돌고 있나요?",question_en:"Is the condenser fan running normally?",yes:"hp_q3",no:"hp_r_fan_stop"},hp_q3:{question:"응축기 핀이 먼지·이물질로 많이 막혀 있나요?",question_en:"Are the condenser fins heavily clogged with dust or debris?",yes:"hp_r_cond_clean",no:"hp_q4"},hp_q4:{question:"냉매 충전량이 적정한가요? 과충전 가능성은 없나요?",question_en:"Is the refrigerant charge appropriate? Is overcharge possible?",yes:"hp_q5",no:"hp_r_overcharge2"},hp_q5:{question:"고압 스위치를 리셋하면 바로 다시 동작하나요?",question_en:"Does the high pressure switch trip again immediately after reset?",yes:"hp_r_persistent_hp",no:"hp_r_transient_hp"},hp_r_measure_first:{type:"result",title:"압력 게이지 연결 후 재진단 필요",title_en:"Re-diagnose after connecting pressure gauge",causes:["진단 전 압력 미측정"],causes_en:["Pressure not measured before diagnosis"],steps:["1. 고·저압 게이지 연결","2. 고압 수치 확인 (R22: 15~20 kg/cm², R410A: 25~30 kg/cm²)","3. 이상값 확인 후 원인 탐색"],steps_en:["1. Connect high and low side gauges","2. Check high-side pressure (R22: 15-20 kg/cm², R410A: 25-30 kg/cm²)","3. Identify cause based on abnormal reading"],level:"easy"},hp_r_fan_stop:{type:"result",title:"응축기 팬 정지로 고압 상승",title_en:"High pressure rise from condenser fan stoppage",causes:["팬 모터 불량","캐패시터 불량","이물질 접촉"],causes_en:["Fan motor failure","Capacitor failure","Foreign object contact"],steps:["1. '응축기 팬이 안 돌아간다' 진단 참조","2. 팬 수리 후 고압 정상화 확인"],steps_en:["1. Refer to 'Condenser fan not running' diagnosis","2. Confirm high-side pressure normalizes after fan repair"],level:"easy"},hp_r_cond_clean:{type:"result",title:"응축기 오염 - 세척 필요",title_en:"Condenser fouled — cleaning needed",causes:["핀 사이 먼지 축적으로 열방출 저하"],causes_en:["Reduced heat rejection from dust in fins"],steps:["1. 고압 세척기로 응축기 세척","2. 세척 후 고압 정상화 확인","3. 정기 세척 주기 수립"],steps_en:["1. Clean condenser with high-pressure washer","2. Confirm high-side pressure normalizes after cleaning","3. Establish regular cleaning schedule"],level:"easy"},hp_r_overcharge2:{type:"result",title:"냉매 과충전",title_en:"Refrigerant overcharge",causes:["이전 충전 시 과다 충전"],causes_en:["Overcharged during previous service"],steps:["1. 소량씩 냉매 회수 (100g 단위)","2. 고압 정상 범위 도달 시 중단","3. 저압 동시 확인하며 최적 조정"],steps_en:["1. Recover refrigerant in small amounts (100g increments)","2. Stop when high-side reaches normal range","3. Simultaneously monitor low-side for optimal adjustment"],level:"medium"},hp_r_persistent_hp:{type:"result",title:"지속적 고압 상승 - 불응축 가스 의심",title_en:"Persistent high pressure — suspected non-condensable gas",causes:["시스템 내 공기 혼입 (진공 처리 불충분)","냉매 분해 가스 발생"],causes_en:["Air in system from insufficient evacuation","Gas from refrigerant decomposition"],steps:["1. 냉매 완전 회수","2. -1 kPa 이하까지 진공 작업 (30분 이상)","3. 진공 유지 확인 (누설 없음)","4. 신규 냉매 재충전"],steps_en:["1. Fully recover refrigerant","2. Evacuate to below -1 kPa (at least 30 minutes)","3. Confirm vacuum is maintained (no leaks)","4. Recharge with new refrigerant"],level:"hard"},hp_r_transient_hp:{type:"result",title:"일시적 고압 상승",title_en:"Transient high pressure rise",causes:["기동 직후 일시 고압","고온 환경에서 운전"],causes_en:["Temporary high pressure right after startup","Operation in high-temperature environment"],steps:["1. 기계실 주변 온도 측정 (40℃ 이하 권장)","2. 환기 개선","3. HPS 설정값 적정성 재확인"],steps_en:["1. Measure ambient temperature around machine room (40°C or below recommended)","2. Improve ventilation","3. Re-verify HPS setpoint appropriateness"],level:"easy"},lp_q1:{question:"사이트글라스에 기포가 보이나요?",question_en:"Are bubbles visible in the sight glass?",yes:"lp_r_leak",no:"lp_q2"},lp_q2:{question:"증발기에 서리가 두껍게 끼어 있나요?",question_en:"Is there heavy frost buildup on the evaporator?",yes:"lp_r_frost_block",no:"lp_q3"},lp_q3:{question:"팽창밸브 감온통이 흡입관에 단단히 밀착되어 있나요?",question_en:"Is the expansion valve sensing bulb firmly attached to the suction line?",yes:"lp_q4",no:"lp_r_bulb"},lp_q4:{question:"팽창밸브 입구 배관이 얼어 있거나 과도하게 차갑나요?",question_en:"Is the expansion valve inlet pipe frozen or excessively cold?",yes:"lp_r_ice_plug",no:"lp_q5"},lp_q5:{question:"흡입 스트레이너를 청소한 지 6개월 이상 됐나요?",question_en:"Has it been more than 6 months since the suction strainer was last cleaned?",yes:"lp_r_strainer2",no:"lp_r_txv_adj"},lp_r_leak:{type:"result",title:"냉매 누설 - 저압 하강",title_en:"Refrigerant leak — low pressure dropping",causes:["배관 누설로 냉매량 감소"],causes_en:["Refrigerant quantity reduced from piping leak"],steps:["1. 전체 배관 누설 점검","2. 누설 수리 후 진공 작업","3. 냉매 재충전","4. LPS 리셋"],steps_en:["1. Inspect all piping for leaks","2. Repair leak, then evacuate","3. Recharge refrigerant","4. Reset LPS"],level:"medium"},lp_r_frost_block:{type:"result",title:"착상으로 인한 저압 하강",title_en:"Low pressure drop from frost blockage",causes:["증발기 착상으로 냉매 증발 불량"],causes_en:["Poor refrigerant evaporation from evaporator frosting"],steps:["1. 강제 제상 실시","2. 제상 완료 후 LPS 리셋","3. 제상 시스템 점검"],steps_en:["1. Run forced defrost","2. Reset LPS after defrost completes","3. Inspect defrost system"],level:"easy"},lp_r_bulb:{type:"result",title:"팽창밸브 감온통 밀착 불량",title_en:"Poor expansion valve sensing bulb contact",causes:["감온통 고정 불량","단열 처리 누락"],causes_en:["Sensing bulb not properly secured","Insulation missing"],steps:["1. 감온통을 흡입관에 단단히 고정 (클램프 사용)","2. 단열 테이프로 감온통 주변 단열 처리","3. 저압 정상화 확인"],steps_en:["1. Firmly secure sensing bulb to suction line (use clamp)","2. Insulate around sensing bulb with insulating tape","3. Confirm low-side pressure normalizes"],level:"easy"},lp_r_ice_plug:{type:"result",title:"팽창밸브 빙결 (수분 결빙)",title_en:"Expansion valve ice plugging (moisture freezing)",causes:["시스템 내 수분으로 팽창밸브 결빙"],causes_en:["Moisture in system freezing at expansion valve"],steps:["1. 온수 수건으로 팽창밸브 해빙","2. 드라이어 교체 (수분 제거)","3. 진공 작업 후 재충전"],steps_en:["1. Thaw expansion valve with warm towel","2. Replace filter-drier (moisture removal)","3. Evacuate and recharge"],level:"medium"},lp_r_strainer2:{type:"result",title:"흡입 스트레이너 막힘",title_en:"Suction strainer clogged",causes:["이물질·슬러지 축적"],causes_en:["Debris and sludge accumulation"],steps:["1. 흡입 스트레이너 분해 세척","2. 손상 시 교체","3. 세척 후 저압 정상화 확인"],steps_en:["1. Disassemble and clean suction strainer","2. Replace if damaged","3. Confirm low-side pressure normalizes after cleaning"],level:"easy"},lp_r_txv_adj:{type:"result",title:"팽창밸브 개도 조정 필요",title_en:"Expansion valve opening adjustment needed",causes:["팽창밸브 개도 너무 좁음","팽창밸브 내부 불량"],causes_en:["Expansion valve opening too narrow","Expansion valve internal failure"],steps:["1. 팽창밸브를 시계 반대 방향으로 1회전 조정","2. 10분 대기 후 저압 변화 확인","3. 개선 없으면 팽창밸브 교체 검토"],steps_en:["1. Adjust expansion valve 1 turn counterclockwise","2. Wait 10 minutes and check low-side pressure change","3. Consider replacing expansion valve if no improvement"],level:"medium"},ef_q1:{question:"팬 모터에 전원이 공급되고 있나요? (단자 전압 측정)",question_en:"Is power being supplied to the fan motor? (measure terminal voltage)",yes:"ef_q2",no:"ef_q1n"},ef_q1n:{question:"제상(디프로스트) 중이거나 제상 후 팬 지연 타이머 동작 중인가요?",question_en:"Is it currently defrosting, or is the post-defrost fan delay timer active?",yes:"ef_r_normal_defrost",no:"ef_q1n_n"},ef_q1n_n:{question:"팬 모터 공급 릴레이 또는 컨트롤러 출력이 정상인가요?",question_en:"Is the fan motor supply relay or controller output normal?",yes:"ef_r_wiring_fan",no:"ef_r_relay_fan"},ef_q2:{question:"팬을 손으로 돌려봤을 때 자유롭게 돌아가나요? (저항 없이)",question_en:"Does the fan turn freely by hand? (without resistance)",yes:"ef_q3",no:"ef_q2n"},ef_q2n:{question:"팬 블레이드에 얼음이 끼어 회전이 막혀 있나요?",question_en:"Is ice buildup on the fan blade preventing rotation?",yes:"ef_r_ice_fan",no:"ef_r_bearing_fan"},ef_q3:{question:"팬 캐패시터 용량을 측정했나요? 정격 ±20% 이내인가요?",question_en:"Have you measured the fan capacitor? Is it within ±20% of rated capacity?",yes:"ef_q4",no:"ef_r_cap_fan"},ef_q4:{question:"모터 권선 저항을 측정했을 때 정상 범위인가요?",question_en:"Is the motor winding resistance within normal range?",yes:"ef_r_motor_other",no:"ef_r_motor_winding"},ef_r_normal_defrost:{type:"result",title:"정상 - 제상 중 팬 정지",title_en:"Normal — fan stopped during defrost",causes:["제상 중 팬 정지는 정상 동작"],causes_en:["Fan stopping during defrost is normal operation"],steps:["1. 제상 완료까지 대기","2. 팬 지연 타이머 설정 확인 (제상 후 2~3분 후 재기동)","3. 제상 완료 후에도 팬이 안 돌면 다시 진단"],steps_en:["1. Wait for defrost to complete","2. Check fan delay timer setting (should restart 2-3 min after defrost)","3. Re-diagnose if fan still doesn't run after defrost"],level:"easy"},ef_r_wiring_fan:{type:"result",title:"팬 모터 배선 단선",title_en:"Fan motor wiring open circuit",causes:["단자 이완","배선 단선"],causes_en:["Terminal loose","Wiring broken"],steps:["1. 팬 모터 배선 전체 점검","2. 단자 조임 및 단선 구간 교체"],steps_en:["1. Inspect all fan motor wiring","2. Tighten terminals and replace broken sections"],level:"easy"},ef_r_relay_fan:{type:"result",title:"팬 공급 릴레이 불량",title_en:"Fan supply relay failure",causes:["릴레이 코일 단선","릴레이 접점 소손"],causes_en:["Relay coil open circuit","Relay contact burned"],steps:["1. 릴레이 동작 확인 (딸깍 소리)","2. 릴레이 코일 전압·저항 측정","3. 동일 규격 릴레이로 교체"],steps_en:["1. Check relay operation (click sound)","2. Measure relay coil voltage and resistance","3. Replace with same-spec relay"],level:"easy"},ef_r_ice_fan:{type:"result",title:"얼음으로 팬 회전 막힘",title_en:"Fan rotation blocked by ice",causes:["착상 과다로 팬 블레이드에 얼음 접촉"],causes_en:["Excessive frost causing ice contact on fan blade"],steps:["1. 강제 제상으로 얼음 제거","2. 제상 완료 후 팬 재기동 확인","3. 제상 설정 점검 (착상 과다 원인 해결)"],steps_en:["1. Remove ice with forced defrost","2. Confirm fan restarts after defrost","3. Check defrost settings (resolve excessive frosting cause)"],level:"easy"},ef_r_bearing_fan:{type:"result",title:"팬 모터 베어링 고착",title_en:"Fan motor bearing seized",causes:["베어링 마모 후 고착","이물질에 의한 고착"],causes_en:["Bearing seized after wear","Seizure from foreign object"],steps:["1. 이물질 제거 후 재시도","2. 개선 없으면 팬 모터 교체","3. 동일 규격(전압, rpm, 축 방향) 모터 구입"],steps_en:["1. Remove foreign objects and retry","2. Replace fan motor if no improvement","3. Purchase motor with same specs (voltage, rpm, shaft direction)"],level:"easy"},ef_r_cap_fan:{type:"result",title:"팬 캐패시터 불량",title_en:"Fan capacitor defective",causes:["캐패시터 용량 저하 또는 개방"],causes_en:["Capacitor capacity reduced or open"],steps:["1. 동일 규격 캐패시터(μF, V)로 교체","2. 교체 후 팬 정상 회전 확인"],steps_en:["1. Replace with same-spec capacitor (μF, V)","2. Confirm normal fan rotation after replacement"],level:"easy"},ef_r_motor_winding:{type:"result",title:"팬 모터 권선 불량",title_en:"Fan motor winding failure",causes:["권선 단선 또는 단락","절연 저하로 지락"],causes_en:["Winding open or short circuit","Ground fault from insulation degradation"],steps:["1. 팬 모터 전체 교체 (권선 수리는 비경제적)","2. 동일 규격 모터 구입 후 교체"],steps_en:["1. Replace entire fan motor (rewinding is uneconomical)","2. Purchase same-spec motor and replace"],level:"easy"},ef_r_motor_other:{type:"result",title:"팬 모터 기타 내부 불량",title_en:"Other internal fan motor failure",causes:["원심 스위치 불량 (단상)","내부 기계적 결함"],causes_en:["Centrifugal switch failure (single-phase)","Internal mechanical defect"],steps:["1. 팬 모터 교체","2. 교체 후 회전 방향 확인 (역회전 시 두 선 교환)"],steps_en:["1. Replace fan motor","2. Check rotation direction after replacement (swap two wires if reversed)"],level:"easy"},cf_q1:{question:"응축기 팬 모터에 전원이 공급되고 있나요?",question_en:"Is power being supplied to the condenser fan motor?",yes:"cf_q2",no:"cf_q1n"},cf_q1n:{question:"고압 스위치나 온도 스위치가 팬 모터 전원을 차단하고 있나요?",question_en:"Is a high pressure switch or temperature switch cutting power to the fan motor?",yes:"cf_r_switch_cut",no:"cf_r_wiring_cond"},cf_q2:{question:"팬을 손으로 돌려봤을 때 자유롭게 돌아가나요?",question_en:"Does the fan turn freely by hand?",yes:"cf_q3",no:"cf_q2n"},cf_q2n:{question:"팬 블레이드에 이물질(나뭇잎, 비닐 등)이 끼어 있나요?",question_en:"Is there foreign matter (leaves, plastic, etc.) caught in the fan blade?",yes:"cf_r_foreign",no:"cf_r_cond_bearing"},cf_q3:{question:"캐패시터 용량이 정격 ±20% 이내인가요?",question_en:"Is the capacitor capacity within ±20% of rated value?",yes:"cf_q4",no:"cf_r_cond_cap"},cf_q4:{question:"모터 회전 방향이 올바른가요? (에어가 응축기를 통과하는 방향)",question_en:"Is the motor rotating in the correct direction? (air flowing through condenser)",yes:"cf_r_cond_motor",no:"cf_r_wrong_direction"},cf_r_switch_cut:{type:"result",title:"보호 스위치가 팬 정지시킴",title_en:"Protection switch stopping fan",causes:["고압 스위치 동작으로 팬 연동 정지","외기 온도 감지 스위치 동작"],causes_en:["Fan stopped in tandem with HP switch activation","Outdoor temperature sensing switch activated"],steps:["1. 고압 스위치 동작 원인 해결","2. 스위치 리셋 후 팬 재기동 확인"],steps_en:["1. Resolve high pressure switch activation cause","2. Reset switch and confirm fan restarts"],level:"medium"},cf_r_wiring_cond:{type:"result",title:"응축기 팬 배선 불량",title_en:"Condenser fan wiring failure",causes:["배선 단선","단자 이완","릴레이 불량"],causes_en:["Wiring broken","Terminal loose","Relay failure"],steps:["1. 팬 모터 배선 및 단자 전체 점검","2. 단선 구간 교체","3. 릴레이 동작 확인 및 교체"],steps_en:["1. Inspect all fan motor wiring and terminals","2. Replace broken sections","3. Check relay operation and replace if needed"],level:"easy"},cf_r_foreign:{type:"result",title:"이물질로 팬 회전 막힘",title_en:"Fan blocked by foreign object",causes:["외부에서 유입된 이물질"],causes_en:["Foreign object entered from outside"],steps:["1. 전원 차단 후 이물질 완전 제거","2. 팬 블레이드 손상 여부 확인","3. 재기동 테스트"],steps_en:["1. Cut power and fully remove foreign object","2. Check fan blade for damage","3. Test restart"],level:"easy"},cf_r_cond_bearing:{type:"result",title:"응축기 팬 모터 베어링 고착",title_en:"Condenser fan motor bearing seized",causes:["베어링 마모 후 고착"],causes_en:["Bearing seized after wear"],steps:["1. 팬 모터 교체","2. 동일 규격 모터 구입 (전압, rpm, 축 크기 확인)"],steps_en:["1. Replace fan motor","2. Purchase same-spec motor (verify voltage, rpm, shaft size)"],level:"easy"},cf_r_cond_cap:{type:"result",title:"응축기 팬 캐패시터 불량",title_en:"Condenser fan capacitor defective",causes:["캐패시터 노후·팽창으로 용량 저하"],causes_en:["Capacitor aged/bulged causing capacity reduction"],steps:["1. 동일 규격 캐패시터로 교체","2. 팬 정상 회전 확인"],steps_en:["1. Replace with same-spec capacitor","2. Confirm normal fan rotation"],level:"easy"},cf_r_cond_motor:{type:"result",title:"응축기 팬 모터 내부 불량",title_en:"Condenser fan motor internal failure",causes:["권선 단선 또는 단락","베어링 마모"],causes_en:["Winding open or short","Bearing wear"],steps:["1. 팬 모터 전체 교체","2. 교체 후 회전 방향 확인"],steps_en:["1. Replace entire fan motor","2. Check rotation direction after replacement"],level:"easy"},cf_r_wrong_direction:{type:"result",title:"팬 역회전 - 배선 수정 필요",title_en:"Fan rotating in wrong direction — wiring correction needed",causes:["단상: 배선 순서 오류","3상: 두 상 교차 연결"],causes_en:["Single-phase: wiring order error","3-phase: two phases crossed"],steps:["1. 단상이면 시동 권선 배선 두 선 교환","2. 3상이면 임의 두 상 배선 교환","3. 교체 후 회전 방향 재확인"],steps_en:["1. Single-phase: swap the two start winding wires","2. Three-phase: swap any two phase wires","3. Re-verify rotation direction after swap"],level:"easy"},dr_q1:{question:"물이 냉동실 내부 바닥에 고이거나 흘러나오고 있나요?",question_en:"Is water pooling on the floor inside the freezer or flowing out?",yes:"dr_q2",no:"dr_q1n"},dr_q1n:{question:"물이 냉동기 외부(기계실 쪽 또는 외부 하단)에서 흘러내리나요?",question_en:"Is water dripping from the exterior of the unit (machine room side or bottom exterior)?",yes:"dr_r_outside",no:"dr_r_check_source"},dr_q2:{question:"증발기(냉각기) 아래 드레인 팬에 물이 가득 차 있나요?",question_en:"Is the drain pan under the evaporator full of water?",yes:"dr_q3",no:"dr_q2n"},dr_q2n:{question:"증발기 착상이 심하게 되어 있나요?",question_en:"Is there heavy frost buildup on the evaporator?",yes:"dr_r_frost_melt",no:"dr_r_door_moisture"},dr_q3:{question:"드레인 배수구가 얼음으로 막혀 있나요?",question_en:"Is the drain outlet blocked by ice?",yes:"dr_r_ice_drain",no:"dr_q4"},dr_q4:{question:"드레인 호스(배수관)가 꺾이거나 역경사가 있나요?",question_en:"Is the drain hose kinked or running uphill?",yes:"dr_r_hose_kinked",no:"dr_r_drain_dirty"},dr_r_outside:{type:"result",title:"외부 결로 또는 냉매 누설 확인 필요",title_en:"External condensation or refrigerant leak needs checking",causes:["배관 보온 불량으로 결로","냉매 누설 후 오일 흘림"],causes_en:["Condensation from poor pipe insulation","Oil dripping from refrigerant leak"],steps:["1. 배관 보온 상태 점검 및 보완","2. 냉매 누설 여부 점검 (비눗물)","3. 오일 자국이 있으면 누설 수리"],steps_en:["1. Inspect and improve pipe insulation","2. Check for refrigerant leaks (soapy water)","3. Repair leak if oil marks are present"],level:"medium"},dr_r_check_source:{type:"result",title:"물 발생 위치 추가 확인 필요",title_en:"Need to further identify water source",causes:["결로, 누설, 배수 등 다양한 원인 가능"],causes_en:["Possible causes include condensation, leakage, drainage"],steps:["1. 냉동기 전체를 꼼꼼히 점검하여 물 발생 위치 특정","2. 배관 연결부, 드레인, 외피 결로 순으로 확인"],steps_en:["1. Carefully inspect entire unit to locate water source","2. Check piping joints, drain, and external condensation in order"],level:"easy"},dr_r_frost_melt:{type:"result",title:"착상 해빙수로 인한 범람",title_en:"Overflow from melting frost",causes:["과도한 착상 후 제상 시 물 과다 발생"],causes_en:["Excessive water produced when heavy frost melts during defrost"],steps:["1. 강제 제상으로 착상 제거","2. 드레인 배수구 청소","3. 착상 과다 원인 해결 (제상 설정 조정)"],steps_en:["1. Remove frost with forced defrost","2. Clean drain outlet","3. Resolve excessive frosting cause (adjust defrost settings)"],level:"easy"},dr_r_door_moisture:{type:"result",title:"도어 패킹 불량으로 외부 습기 유입",title_en:"External moisture ingress from door gasket failure",causes:["패킹 손상으로 외부 공기 유입 → 결로"],causes_en:["External air ingress from damaged gasket → condensation"],steps:["1. 도어 패킹 밀착 확인 (종이 테스트)","2. 불량 시 패킹 교체","3. 힌지 처짐 확인 및 조정"],steps_en:["1. Check door gasket seal (paper test)","2. Replace gasket if faulty","3. Check for door sag and adjust hinges"],level:"easy"},dr_r_ice_drain:{type:"result",title:"드레인 배수구 얼음 막힘",title_en:"Drain outlet blocked by ice",causes:["제상수가 배수구에서 재결빙"],causes_en:["Defrost water refreezing at drain outlet"],steps:["1. 온수로 배수구 얼음 녹임","2. 드레인 히터 설치 여부 확인 (없으면 설치 검토)","3. 배수구 단열 강화"],steps_en:["1. Melt ice at drain outlet with hot water","2. Check if drain heater is installed (consider installing if absent)","3. Improve drain outlet insulation"],level:"easy"},dr_r_hose_kinked:{type:"result",title:"드레인 호스 꺾임 또는 역경사",title_en:"Drain hose kinked or running uphill",causes:["설치 시 배관 경로 불량","호스 변형"],causes_en:["Poor routing during installation","Hose deformation"],steps:["1. 드레인 호스 전체 경로 확인","2. 꺾인 부분 교정 또는 교체","3. 배수 방향으로 일정한 하강 경사 확보 (최소 1/50 이상)"],steps_en:["1. Check entire drain hose routing","2. Correct or replace kinked sections","3. Ensure consistent downward slope toward drain (at least 1/50)"],level:"easy"},dr_r_drain_dirty:{type:"result",title:"드레인 배수구 이물질 막힘",title_en:"Drain outlet clogged with debris",causes:["먼지, 슬러지, 곰팡이 등 이물질 퇴적"],causes_en:["Accumulation of dust, sludge, mold, etc."],steps:["1. 배수구 와이어 또는 솔로 청소","2. 온수로 배수구 세척","3. 배수 정상 확인"],steps_en:["1. Clean drain outlet with wire or brush","2. Flush drain with hot water","3. Confirm normal drainage"],level:"easy"},np_q1:{question:"냉동기 콘센트(또는 전원 입력부)에서 전압이 측정되나요?",question_en:"Is voltage measured at the unit's power outlet or input terminal?",yes:"np_q2",no:"np_r_no_power"},np_q2:{question:"전원 코드나 인입 배선에 육안 손상(절단, 눌림, 피복 손상)이 있나요?",question_en:"Is there visible damage to the power cord or supply wiring (cuts, kinks, insulation damage)?",yes:"np_r_cord_damage",no:"np_q3"},np_q3:{question:"판넬 내부 메인 차단기 또는 퓨즈가 트립/단선되어 있나요?",question_en:"Is the main breaker or fuse inside the panel tripped or blown?",yes:"np_r_internal_breaker",no:"np_q4"},np_q4:{question:"컨트롤러 전원 단자에서 전압이 나오고 있나요?",question_en:"Is voltage present at the controller power terminals?",yes:"np_q5",no:"np_r_panel_wiring"},np_q5:{question:"컨트롤러(PCB) 표면에 탄 자국, 부품 파손, 전해콘덴서 팽창 흔적이 있나요?",question_en:"Are there burn marks, broken components, or bulging electrolytic capacitors on the controller PCB?",yes:"np_r_pcb_burned",no:"np_r_pcb_fault"},np_r_no_power:{type:"result",title:"외부 전원 없음",title_en:"No external power",causes:["건물 메인 차단기 트립","정전","인입 케이블 단선"],causes_en:["Building main breaker tripped","Power outage","Supply cable broken"],steps:["1. 건물 메인 차단기 확인","2. 인근 다른 기기 전원 확인으로 정전 여부 판단","3. 인입 케이블 점검"],steps_en:["1. Check building main breaker","2. Check power at nearby equipment to determine if there's an outage","3. Inspect supply cable"],level:"easy"},np_r_cord_damage:{type:"result",title:"전원 코드 또는 인입 배선 손상",title_en:"Power cord or supply wiring damaged",causes:["기계적 손상 (압착, 절단)","설치 불량"],causes_en:["Mechanical damage (pinching, cutting)","Poor installation"],steps:["1. 손상 구간 교체 (전원 코드 또는 배선)","2. 배선 경로를 물리적 손상에서 보호되게 재배선","3. 교체 후 절연저항 측정"],steps_en:["1. Replace damaged section (cord or wiring)","2. Reroute wiring to protect from physical damage","3. Measure insulation resistance after replacement"],level:"medium"},np_r_internal_breaker:{type:"result",title:"판넬 내부 차단기 트립",title_en:"Internal panel breaker tripped",causes:["과전류 또는 단락으로 트립"],causes_en:["Tripped from overcurrent or short circuit"],steps:["1. 차단기 트립 원인 파악 (단락? 과전류?)","2. 원인 해결 후 리셋","3. '전기가 자꾸 끊긴다' 진단 참조"],steps_en:["1. Determine cause of breaker trip (short? overcurrent?)","2. Resolve cause then reset","3. Refer to 'circuit breaker keeps tripping' diagnosis"],level:"medium"},np_r_panel_wiring:{type:"result",title:"판넬 내부 배선 불량",title_en:"Internal panel wiring failure",causes:["단자 이완","배선 단선"],causes_en:["Terminal loose","Wiring broken"],steps:["1. 판넬 내부 배선 전체 점검","2. 단자 조임 및 단선 구간 교체"],steps_en:["1. Inspect all internal panel wiring","2. Tighten terminals and replace broken sections"],level:"medium"},np_r_pcb_burned:{type:"result",title:"컨트롤러 PCB 소손",title_en:"Controller PCB burned out",causes:["서지 전압에 의한 PCB 파손","과전류로 인한 부품 소손"],causes_en:["PCB damaged from voltage surge","Component burnout from overcurrent"],steps:["1. 동일 모델 컨트롤러 PCB 구입","2. 교체 전 입력 전압 안정 여부 확인","3. PCB 교체 후 기동 테스트"],steps_en:["1. Purchase same-model controller PCB","2. Verify input voltage stability before replacement","3. Test startup after PCB replacement"],level:"hard"},np_r_pcb_fault:{type:"result",title:"컨트롤러 내부 불량 (육안 이상 없음)",title_en:"Controller internal failure (no visible damage)",causes:["내부 마이크로컨트롤러 불량","펌웨어 오류"],causes_en:["Internal microcontroller failure","Firmware error"],steps:["1. 컨트롤러 전원 완전 차단 후 5분 후 재공급 (리셋)","2. 개선 없으면 동일 모델 컨트롤러 교체","3. 교체 시 파라미터 설정 재입력"],steps_en:["1. Fully cut controller power, wait 5 minutes, then restore (reset)","2. If no improvement, replace with same-model controller","3. Re-enter parameters after replacement"],level:"hard"}};export{e as categories,t as nodes};
